import React, { useState, useEffect } from 'react';
import { Routes, Route, useNavigate, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import CustomerManagement from './pages/CustomerManagement';
import CustomerDetails from './pages/CustomerDetails';
import Reports from './pages/Reports';
import UserManagement from './pages/UserManagement';
import LoginPage from './pages/LoginPage';
import { Customer, Transaction, User, UserRoleEnum, NewCustomerData } from './types';
import * as api from './api'; // Import the new API service

const App: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const navigate = useNavigate();

  // Effect for initial app load and authentication check
  useEffect(() => {
    const initializeApp = async () => {
      const token = localStorage.getItem('authToken');
      if (token) {
        try {
          const user = await api.getLoggedInUser();
          setCurrentUser(user);
          // If user is authenticated, fetch all necessary data
          const [customersData, usersData, transactionsData] = await Promise.all([
            api.getCustomers(),
            api.getUsers(),
            api.getTransactions(),
          ]);
          setCustomers(customersData);
          setUsers(usersData);
          setTransactions(transactionsData);

          // Redirect after data is loaded
          if (user.role === UserRoleEnum.KUNDE && user.associatedCustomerId) {
            navigate(`/customers/${user.associatedCustomerId}`, { replace: true });
          }

        } catch (err) {
          console.error("Initialization failed:", err);
          // Token is invalid or expired
          localStorage.removeItem('authToken');
          setCurrentUser(null);
          navigate('/login', { replace: true });
        }
      } else {
        navigate('/login', { replace: true });
      }
      setIsLoading(false);
    };

    initializeApp();
  }, [navigate]); // navigate is stable, so this runs once on mount

  const handleLogin = async (email: string, passwordInput: string): Promise<boolean> => {
    try {
      const { token, user } = await api.login(email, passwordInput);
      localStorage.setItem('authToken', token);
      setCurrentUser(user);
      setIsLoading(true); // Show loading screen while fetching data
      // Fetch all data after successful login
      const [customersData, usersData, transactionsData] = await Promise.all([
        api.getCustomers(),
        api.getUsers(),
        api.getTransactions(),
      ]);
      setCustomers(customersData);
      setUsers(usersData);
      setTransactions(transactionsData);
      setIsLoading(false);

      if (user.role === UserRoleEnum.KUNDE && user.associatedCustomerId) {
        navigate(`/customers/${user.associatedCustomerId}`, { replace: true });
      } else {
        navigate('/', { replace: true });
      }
      return true;
    } catch (err) {
      console.error('Login failed:', err);
      return false;
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('authToken');
    setCurrentUser(null);
    setCustomers([]);
    setUsers([]);
    setTransactions([]);
    alert('Sie wurden abgemeldet.');
    navigate('/login', { replace: true });
  };

  const handleAddCustomer = async (customerData: NewCustomerData) => {
    try {
      const newCustomer = await api.addCustomer(customerData);
      // Refetch both customers and users, as adding a customer might create a user account
      const [customersData, usersData] = await Promise.all([api.getCustomers(), api.getUsers()]);
      setCustomers(customersData);
      setUsers(usersData);
    } catch (err) {
      console.error("Failed to add customer:", err);
      alert("Fehler beim Hinzufügen des Kunden.");
    }
  };

  const handleUpdateCustomer = async (updatedCustomerData: Customer) => {
    try {
      const updatedCustomer = await api.updateCustomer(updatedCustomerData.id, updatedCustomerData);
      setCustomers(prev => prev.map(c => (c.id === updatedCustomer.id ? updatedCustomer : c)));
      // Also, update the corresponding user if their details changed
      const userToUpdate = users.find(u => u.associatedCustomerId === updatedCustomer.id);
      if (userToUpdate && (userToUpdate.email !== updatedCustomer.email || userToUpdate.firstName !== updatedCustomer.firstName || userToUpdate.lastName !== updatedCustomer.lastName)) {
        const updatedUser = await api.updateUser(userToUpdate.id, {
            firstName: updatedCustomer.firstName,
            lastName: updatedCustomer.lastName,
            email: updatedCustomer.email,
        });
        setUsers(prev => prev.map(u => u.id === updatedUser.id ? updatedUser : u));
      }
    } catch (err) {
      console.error("Failed to update customer:", err);
      alert("Fehler beim Aktualisieren des Kunden.");
    }
  };

  const handleAddTransaction = async (newTransaction: Transaction) => {
     try {
      // The API should handle setting the date and employee based on the authenticated user.
      const transactionToAdd = {
        customerId: newTransaction.customerId,
        type: newTransaction.type,
        description: newTransaction.description,
        amount: newTransaction.amount,
      };
      await api.addTransaction(transactionToAdd);
      // Refetch transactions and customers to get updated balance
      const [transactionsData, customersData] = await Promise.all([api.getTransactions(), api.getCustomers()]);
      setTransactions(transactionsData);
      setCustomers(customersData);
    } catch (err) {
      console.error("Failed to add transaction:", err);
      alert("Fehler beim Hinzufügen der Transaktion.");
    }
  };

  const handleAddUser = async (newUser: User) => {
    try {
      await api.addUser(newUser);
      setUsers(await api.getUsers());
      // If a customer user was added, their associated customer record might need to be created/refreshed
      if (newUser.role === UserRoleEnum.KUNDE) {
          setCustomers(await api.getCustomers());
      }
    } catch (err) {
      console.error("Failed to add user:", err);
      alert("Fehler beim Hinzufügen des Benutzers.");
    }
  };

  const handleUpdateUser = async (updatedUserData: User) => {
    try {
      const updatedUser = await api.updateUser(updatedUserData.id, updatedUserData);
      setUsers(prev => prev.map(u => (u.id === updatedUser.id ? updatedUser : u)));
      // If a customer's user account is updated, sync it with the customer record
      if (updatedUser.role === UserRoleEnum.KUNDE && updatedUser.associatedCustomerId) {
        setCustomers(await api.getCustomers());
      }
    } catch (err) {
      console.error("Failed to update user:", err);
      alert("Fehler beim Aktualisieren des Benutzers.");
    }
  };

  const handleDeleteUser = async (userId: string) => {
    try {
      await api.deleteUser(userId);
      setUsers(users.filter(u => u.id !== userId));
      // Optional: Refetch customers if a customer user was deleted
      setCustomers(await api.getCustomers());
    } catch (err) {
      console.error("Failed to delete user:", err);
      alert("Fehler beim Löschen des Benutzers.");
    }
  };

  // Render a global loading screen until the app is initialized
  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-screen w-full bg-gray-100">
        <p className="text-xl text-gray-700 animate-pulse">Lade Anwendung...</p>
      </div>
    );
  }

  return (
    <div className="flex min-h-screen bg-gray-100">
      {currentUser ? (
        <>
          <Sidebar appName="Mantrailing Card" currentUser={currentUser} onLogout={handleLogout} />
          <main className="flex-1 md:ml-64 p-0">
            <Routes>
              {currentUser.role === UserRoleEnum.ADMIN ? (
                <>
                  <Route path="/" element={<Dashboard customers={customers} transactions={transactions} />} />
                  <Route path="/customers" element={<CustomerManagement customers={customers} transactions={transactions} currentUser={currentUser} onAddCustomer={handleAddCustomer} />} />
                  <Route path="/customers/:id" element={<CustomerDetails customers={customers} transactions={transactions} onUpdateCustomer={handleUpdateCustomer} onAddTransaction={handleAddTransaction} currentUser={currentUser} />} />
                  <Route path="/reports" element={<Reports customers={customers} transactions={transactions} />} />
                  <Route path="/users" element={<UserManagement users={users} onAddUser={handleAddUser} onUpdateUser={handleUpdateUser} onDeleteUser={handleDeleteUser} />} />
                  <Route path="*" element={<Navigate replace to="/" />} />
                </>
              ) : currentUser.role === UserRoleEnum.MITARBEITER ? (
                <>
                  <Route path="/" element={<Dashboard customers={customers} transactions={transactions} />} />
                  <Route path="/customers" element={<CustomerManagement customers={customers} transactions={transactions} currentUser={currentUser} onAddCustomer={handleAddCustomer} />} />
                  <Route path="/customers/:id" element={<CustomerDetails customers={customers} transactions={transactions} onUpdateCustomer={handleUpdateCustomer} onAddTransaction={handleAddTransaction} currentUser={currentUser} />} />
                  <Route path="*" element={<Navigate replace to="/" />} />
                </>
              ) : currentUser.role === UserRoleEnum.KUNDE && currentUser.associatedCustomerId ? (
                <>
                  <Route path="/customers/:id" element={<CustomerDetails customers={customers} transactions={transactions} onUpdateCustomer={handleUpdateCustomer} onAddTransaction={handleAddTransaction} currentUser={currentUser} />} />
                  <Route path="*" element={<Navigate replace to={`/customers/${currentUser.associatedCustomerId}`} />} />
                </>
              ) : (
                <Route path="*" element={<Navigate replace to="/login" />} />
              )}
            </Routes>
          </main>
        </>
      ) : (
        <Routes>
          <Route path="/login" element={<LoginPage onLogin={handleLogin} />} />
          <Route path="*" element={<Navigate replace to="/login" />} />
        </Routes>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import Card from '../components/Card';
import Input from '../components/Input';
import Button from '../components/Button';

interface LoginPageProps {
  onLogin: (email: string, password: string) => Promise<boolean>;
}

const LoginPage: React.FC<LoginPageProps> = ({ onLogin }) => {
  const [email, setEmail] = useState('admin@pfotencard.de');
  const [password, setPassword] = useState('adminpassword');
  const [emailError, setEmailError] = useState('');
  const [passwordError, setPasswordError] = useState('');
  const [loginError, setLoginError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const validateForm = () => {
    let isValid = true;
    setEmailError('');
    setPasswordError('');
    setLoginError('');

    if (!email.trim()) {
      setEmailError('E-Mail ist erforderlich.');
      isValid = false;
    } else if (!/\S+@\S+\.\S+/.test(email)) {
      setEmailError('Ungültiges E-Mail-Format.');
      isValid = false;
    }

    if (!password.trim()) {
      setPasswordError('Passwort ist erforderlich.');
      isValid = false;
    }

    return isValid;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validateForm() || isLoading) return;

    setIsLoading(true);
    try {
      const success = await onLogin(email, password);
      if (!success) {
        setLoginError('Ungültige E-Mail oder ungültiges Passwort.');
      }
    } catch (error) {
        setLoginError(error instanceof Error ? error.message : 'Ein unerwarteter Fehler ist aufgetreten.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex items-center justify-center min-h-screen w-full bg-gray-100 p-4">
      <Card className="max-w-md w-full p-8">
        <h1 className="text-3xl font-bold text-gray-900 text-center mb-6">Mantrailing Card</h1>
        <p className="text-gray-600 text-center mb-8">Melden Sie sich an, um fortzufahren</p>

        <form onSubmit={handleSubmit} className="space-y-6">
          <Input
            id="loginEmail"
            label="E-Mail"
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="ihre.email@example.com"
            error={emailError}
            disabled={isLoading}
          />
          <Input
            id="loginPassword"
            label="Passwort"
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="********"
            error={passwordError}
            disabled={isLoading}
          />

          {loginError && (
            <div className="text-red-600 text-sm text-center -mt-4">
              {loginError}
            </div>
          )}

          <Button type="submit" variant="primary" className="w-full" disabled={isLoading}>
            {isLoading ? 'Anmelden...' : 'Anmelden'}
          </Button>
        </form>
      </Card>
    </div>
  );
};

export default LoginPage;

