// In a real app, this would come from an environment variable.
// This is a placeholder for your actual backend API URL.
const API_BASE_URL = '/api'; 

const getToken = (): string | null => {
  return localStorage.getItem('authToken');
};

const fetchApi = async (endpoint: string, options: RequestInit = {}): Promise<any> => {
  const token = getToken();
  // FIX: The original spread syntax for headers is incorrect for HeadersInit which can be string[][].
  // Using the Headers constructor normalizes various header formats into a consistent object.
  const headers = new Headers(options.headers);

  // All API calls in this app send JSON, so we ensure the Content-Type is set correctly.
  headers.set('Content-Type', 'application/json');

  if (token) {
    headers.set('Authorization', `Bearer ${token}`);
  }

  try {
    const response = await fetch(`${API_BASE_URL}${endpoint}`, { ...options, headers });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({ message: response.statusText }));
      throw new Error(errorData.message || 'Ein Serverfehler ist aufgetreten');
    }

    if (response.status === 204) { // Handle No Content response
      return null;
    }

    return response.json();
  } catch (error) {
    console.error(`API call to ${endpoint} failed:`, error);
    throw error; // Re-throw the error to be caught by the calling function
  }
};

