interface CustomerDetailsProps {
  customers: Customer[];
  transactions: Transaction[];
  onUpdateCustomer: (updatedCustomer: Customer) => void;
  onAddTransaction: (newTransaction: Transaction) => void;
  currentUser: User;
}

const CustomerDetails: React.FC<CustomerDetailsProps> = ({
  customers,
  transactions,
  onUpdateCustomer,
  onAddTransaction,
  currentUser,
}) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [showConfirmationModal, setShowConfirmationModal] = useState(false);
  const [showTransactionTypeModal, setShowTransactionTypeModal] = useState(false);
  const [isTransactionHistoryModalOpen, setIsTransactionHistoryModalOpen] = useState(false);
  const [transactionData, setTransactionData] = useState<TransactionConfirmationData | null>(null);
  const [customer, setCustomer] = useState<Customer | null>(null);
  const [isLoadingCustomer, setIsLoadingCustomer] = useState(true);
  const [isEditMode, setIsEditMode] = useState(false);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editableData, setEditableData] = useState({
    phone: '',
    dogName: '',
    chipNumber: '',
  });

  useEffect(() => {
    setIsLoadingCustomer(true);
    if (id) {
      const foundCustomer = customers.find((c) => c.id === id);
      setCustomer(foundCustomer || null);

      if (foundCustomer) {
        setEditableData({
          phone: foundCustomer.phone,
          dogName: foundCustomer.dogName,
          chipNumber: foundCustomer.chipNumber,
        });
      }
    } else {
      setCustomer(null);
    }
    setIsLoadingCustomer(false);
  }, [id, customers]);

  // Authorization Effect: Redirect if a customer tries to access another customer's page
  useEffect(() => {
    if (currentUser.role === UserRoleEnum.KUNDE && currentUser.associatedCustomerId && id !== currentUser.associatedCustomerId) {
        navigate(`/customers/${currentUser.associatedCustomerId}`, { replace: true });
    }
  }, [currentUser, id, navigate]);

  const [expandedSections, setExpandedSections] = useState<Record<number, boolean>>({});

  useEffect(() => {
    if (customer) {
      setExpandedSections(prev => {
        const newExpanded = { ...prev };
        customer.trainingProgress.forEach(section => {
          if (newExpanded[section.id] === undefined) {
            newExpanded[section.id] = false;
          }
        });
        return newExpanded;
      });
    }
  }, [customer]);

  // Filter and sort transactions for the current customer
  const customerTransactions = transactions
    .filter(t => t.customerId === id)
    .sort((a, b) => {
      const dateA = new Date(a.date.split('.').reverse().join('-'));
      const dateB = new Date(b.date.split('.').reverse().join('-'));
      return dateB.getTime() - dateA.getTime();
    });

  if (!id) {
    return (
      <div className="p-8 text-center text-red-600">
        Keine Kunden-ID in der URL gefunden.
        <Button variant="primary" onClick={() => navigate('/customers')} className="mt-4">
          Zurück zur Kundenliste
        </Button>
      </div>
    );
  }

  if (isLoadingCustomer) {
    return <div className="p-8 text-center text-gray-600">Lade Kundendaten...</div>;
  }

  if (!customer) {
    return (
      <div className="p-8 text-center text-gray-600">
        Kunde mit ID "{id}" nicht gefunden.
        <Button variant="primary" onClick={() => navigate('/customers')} className="mt-4">
          Zurück zur Kundenliste
        </Button>
      </div>
    );
  }

  const handleOpenConfirmationModal = (amount: number, type: 'Aufladung' | 'Abbuchung', description?: string) => {
    const oldBalance = customer.balance;
    const newBalance = type === 'Aufladung' ? oldBalance + amount : oldBalance - amount;
    setTransactionData({
      customerId: customer.id,
      customerName: `${customer.firstName} ${customer.lastName}`,
      employee: CURRENT_EMPLOYEE,
      transactionType: type,
      amount: amount,
      oldBalance: oldBalance,
      newBalance: newBalance,
      description: description,
    });
    setShowConfirmationModal(true);
  };

  const handleConfirmTransaction = () => {
    if (!transactionData || !customer) return;

    let finalUpdatedCustomer: Customer = { ...customer };
    finalUpdatedCustomer.balance = transactionData.newBalance;
    finalUpdatedCustomer.totalTransactions = customer.totalTransactions + 1;

    const isRecharge = transactionData.transactionType === 'Aufladung';
    if (!isRecharge && transactionData.description === 'Trails' && transactionData.amount === 18) {
      const currentTrainingProgress = [...customer.trainingProgress];
      let customerOverallLevel = finalUpdatedCustomer.level;
      const currentLevelIndex = currentTrainingProgress.findIndex(s => s.status === 'Aktuell');

      if (currentLevelIndex !== -1) {
        const currentSection = { ...currentTrainingProgress[currentLevelIndex] };
        if (currentSection.name === TrainingLevelEnum.EXPERT) {
          if (currentSection.completedHours < 500) {
            currentSection.completedHours += 1;
            currentTrainingProgress[currentLevelIndex] = currentSection;
          }
        } else if (currentSection.completedHours < currentSection.requiredHours) {
          currentSection.completedHours += 1;
          if (currentSection.completedHours === currentSection.requiredHours) {
            currentSection.status = 'Abgeschlossen';
            const nextLevelIndex = currentLevelIndex + 1;
            if (nextLevelIndex < currentTrainingProgress.length) {
              const nextSection = { ...currentTrainingProgress[nextLevelIndex] };
              nextSection.status = 'Aktuell';
              customerOverallLevel = nextSection.name;
              currentTrainingProgress[nextLevelIndex] = nextSection;
            }
          }
          currentTrainingProgress[currentLevelIndex] = currentSection;
        }
        finalUpdatedCustomer.trainingProgress = currentTrainingProgress;
        finalUpdatedCustomer.level = customerOverallLevel;
      }
    }

    onUpdateCustomer(finalUpdatedCustomer);

    const newTransaction: Transaction = {
      id: `trx-${transactions.length + 1}-${Date.now()}`,
      customerId: customer.id,
      type: transactionData.transactionType === 'Aufladung' ? 'recharge' : 'debit',
      description: transactionData.description || (transactionData.transactionType === 'Aufladung' ? 'Aufladung' : 'Trails'),
      amount: transactionData.amount,
      date: REFERENCE_DATE.toLocaleDateString('de-DE'),
      employee: CURRENT_EMPLOYEE,
    };
    onAddTransaction(newTransaction);
    setShowConfirmationModal(false);
    setTransactionData(null);
  };

  const handleSelectTransactionType = (type: 'Aufladung' | 'Abbuchung') => {
    setShowTransactionTypeModal(false);
    let defaultAmount = type === 'Aufladung' ? 215 : 18;
    let description = type === 'Aufladung' ? 'Guthabenaufladung' : 'Trails';
    handleOpenConfirmationModal(defaultAmount, type, description);
  };

  const handleToggleEditMode = () => {
    if (!isEditMode) {
      setEditableData({
        phone: customer.phone,
        dogName: customer.dogName,
        chipNumber: customer.chipNumber,
      });
    }
    setIsEditMode(!isEditMode);
  };

  const handleCancelEdit = () => {
    setIsEditMode(false);
  };

  const handleSaveChanges = () => {
    const updatedCustomer = {
      ...customer,
      phone: editableData.phone,
      dogName: editableData.dogName,
      chipNumber: editableData.chipNumber,
    };
    onUpdateCustomer(updatedCustomer);
    setIsEditMode(false);
  };

  const handleUpdateStammdaten = (data: NewCustomerData) => {
    if (!customer) return;
    const updatedCustomer = { ...customer, ...data };
    onUpdateCustomer(updatedCustomer);
    setIsEditModalOpen(false);
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { id, value } = e.target;
    setEditableData(prev => ({ ...prev, [id]: value }));
  };

  const getStatusClasses = (status: string) => {
    switch (status) {
      case 'Aktuell': return 'bg-green-100 text-green-800';
      case 'Gesperrt': return 'bg-red-100 text-red-800';
      case 'Abgeschlossen': return 'bg-blue-100 text-blue-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const DataRow: React.FC<{ Icon: React.ElementType; label: string; value: string | number }> = ({ Icon, label, value }) => (
    <div>
      <div className="flex items-center text-gray-500 mb-1">
        <Icon className="h-4 w-4 mr-2" />
        <span className="text-sm font-medium">{label}</span>
      </div>
      <p className="font-semibold text-gray-900 ml-6">{value}</p>
    </div>
  );

  const toggleSection = (sectionId: number) => {
    setExpandedSections(prev => ({ ...prev, [sectionId]: !prev[sectionId] }));
  };

  const getLevelSummaryCardColors = (level: TrainingLevelEnum) => {
    switch (level) {
      case TrainingLevelEnum.EINSTEIGER: return { bg: 'bg-fuchsia-50', text: 'text-fuchsia-700', icon: 'text-fuchsia-700' };
      case TrainingLevelEnum.GRUNDLAGEN: return { bg: 'bg-lime-50', text: 'text-lime-700', icon: 'text-lime-700' };
      case TrainingLevelEnum.FORTGESCHRITTENE: return { bg: 'bg-sky-50', text: 'text-sky-700', icon: 'text-sky-700' };
      case TrainingLevelEnum.MASTERCLASS: return { bg: 'bg-amber-50', text: 'text-amber-700', icon: 'text-amber-700' };
      case TrainingLevelEnum.EXPERT: return { bg: 'bg-indigo-50', text: 'text-indigo-700', icon: 'text-indigo-700' };
      default: return { bg: 'bg-gray-50', text: 'text-gray-700', icon: 'text-gray-700' };
    }
  };

  const levelSummaryColors = getLevelSummaryCardColors(customer.level);
  const canPerformActions = currentUser.role === UserRoleEnum.ADMIN || currentUser.role === UserRoleEnum.MITARBEITER;
  const isCustomerViewing = currentUser.role === UserRoleEnum.KUNDE;

  return (
    <div className="p-6 md:p-8 lg:p-10 min-h-screen">
      <div className="flex items-center justify-between mb-6 flex-wrap gap-4">
        <div className="flex items-center">
          {!isCustomerViewing && (
            <button onClick={() => navigate('/customers')} className="text-gray-500 hover:text-gray-700 mr-4">
              <ArrowLeftIcon className="h-6 w-6" />
            </button>
          )}
          <h1 className="text-2xl font-bold text-gray-900 flex items-center">
            {customer.firstName} {customer.lastName}
            <span className="text-gray-500 font-normal text-base ml-2">
              {isCustomerViewing ? "Meine Übersicht" : "Kundendetails & Übersicht"}
            </span>
          </h1>
        </div>

        {isEditMode ? (
          <div className="flex space-x-3">
            <Button variant="outline" onClick={handleCancelEdit}>Abbrechen</Button>
            <Button variant="success" icon={SaveIcon} onClick={handleSaveChanges}>Speichern</Button>
          </div>
        ) : (
          <div className="flex space-x-3">
            {canPerformActions && (
              <>
                <Button variant="outline" onClick={() => setIsEditModalOpen(true)}>Stammdaten</Button>
                <Button variant="success" onClick={() => setShowTransactionTypeModal(true)}>Transaktionen</Button>
              </>
            )}
            {isCustomerViewing && (
              <Button variant="primary" icon={EditIcon} onClick={handleToggleEditMode}>Meine Daten bearbeiten</Button>
            )}
          </div>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-6">
          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Persönliche Daten</h2>
            <div className="flex items-start">
              <Avatar initials={customer.avatarInitials} color={customer.avatarColor} size="lg" className="mr-6 flex-shrink-0" />
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-12 gap-y-6 flex-grow">
                <DataRow Icon={UserIcon} label="Vorname" value={customer.firstName} />
                <DataRow Icon={UserIcon} label="Nachname" value={customer.lastName} />
                <DataRow Icon={MailIcon} label="E-Mail" value={customer.email} />
                {isEditMode ? (
                  <Input id="phone" label="Telefon" value={editableData.phone} onChange={handleInputChange} />
                ) : (
                  <DataRow Icon={PhoneIcon} label="Telefon" value={customer.phone} />
                )}
                {isEditMode ? (
                  <Input id="dogName" label="Hund" value={editableData.dogName} onChange={handleInputChange} />
                ) : (
                  <DataRow Icon={HeartIcon} label="Hund" value={customer.dogName} />
                )}
                {isEditMode ? (
                  <Input id="chipNumber" label="Chipnummer" value={editableData.chipNumber} onChange={handleInputChange} />
                ) : (
                  <DataRow Icon={CreditCardIcon} label="Chipnummer" value={customer.chipNumber} />
                )}
              </div>
            </div>
          </Card>

          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Übersicht</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="bg-green-50 p-4 rounded-lg flex flex-col justify-center items-center text-center">
                <p className="text-sm text-gray-600 mb-1">Aktuelles Guthaben</p>
                <p className="text-2xl font-bold text-green-700">{customer.balance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}</p>
              </div>
              <button
                onClick={() => setIsTransactionHistoryModalOpen(true)}
                className="bg-blue-50 p-4 rounded-lg flex flex-col justify-center items-center text-center w-full hover:bg-blue-100 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 transition-colors"
              >
                <p className="text-sm text-gray-600 mb-1">Transaktionen gesamt</p>
                <p className="text-2xl font-bold text-blue-700">{customer.totalTransactions}</p>
              </button>
              <div className={`${levelSummaryColors.bg} p-4 rounded-lg flex flex-col justify-center items-center text-center`}>
                <p className="text-sm text-gray-600 mb-1">Level</p>
                <div className="flex items-center mt-2">
                  <AwardIcon className={`h-10 w-10 mr-2 ${levelSummaryColors.icon}`} />
                  <p className={`text-2xl font-bold ${levelSummaryColors.text}`}>{customer.level}</p>
                </div>
              </div>
            </div>
          </Card>

          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Ausbildungsfortschritt</h2>
            <div className="space-y-6">
              {customer.trainingProgress.map((section) => {
                let headerBgClass = 'bg-gray-50';
                let levelCircleBgClass = 'bg-gray-400';

                switch (section.name) {
                  case TrainingLevelEnum.EINSTEIGER: headerBgClass = 'bg-fuchsia-50'; break;
                  case TrainingLevelEnum.GRUNDLAGEN: headerBgClass = 'bg-lime-50'; break;
                  case TrainingLevelEnum.FORTGESCHRITTENE: headerBgClass = 'bg-sky-50'; break;
                  case TrainingLevelEnum.MASTERCLASS: headerBgClass = 'bg-amber-50'; break;
                  case TrainingLevelEnum.EXPERT: headerBgClass = 'bg-indigo-50'; break;
                }
                switch (section.name) {
                  case TrainingLevelEnum.EINSTEIGER: levelCircleBgClass = 'bg-fuchsia-500'; break;
                  case TrainingLevelEnum.GRUNDLAGEN: levelCircleBgClass = 'bg-lime-500'; break;
                  case TrainingLevelEnum.FORTGESCHRITTENE: levelCircleBgClass = 'bg-sky-500'; break;
                  case TrainingLevelEnum.MASTERCLASS: levelCircleBgClass = 'bg-amber-500'; break;
                  case TrainingLevelEnum.EXPERT: levelCircleBgClass = 'bg-indigo-500'; break;
                }

                const isExpanded = expandedSections[section.id];
                return (
                  <div key={section.id} className="rounded-lg overflow-hidden border border-gray-200 shadow-sm">
                    <button
                      className={`p-4 flex items-center justify-between w-full text-left ${headerBgClass}`}
                      onClick={() => toggleSection(section.id)}
                      aria-expanded={isExpanded}
                      aria-controls={`section-content-${section.id}`}
                    >
                      <h3 className="text-lg font-medium text-gray-900 flex items-center">
                        <span className={`flex items-center justify-center h-8 w-8 rounded-full text-white font-bold text-base mr-3 ${levelCircleBgClass}`}>{section.id}</span>
                        {section.name}
                      </h3>
                      <div className="flex items-center">
                        <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${getStatusClasses(section.status)} mr-2`}>{section.status}</span>
                        <ChevronDownIcon className={`h-5 w-5 text-gray-500 transition-transform duration-200 ${isExpanded ? 'rotate-180' : ''}`} />
                      </div>
                    </button>
                    <div id={`section-content-${section.id}`} className={`${isExpanded ? 'block' : 'hidden'} p-4 bg-white border-t border-gray-200`}>
                      {section.name === TrainingLevelEnum.EXPERT ? (
                        (() => {
                          const currentHours = section.completedHours;
                          const fullMilestones = Math.floor(currentHours / 100);
                          const remainingHours = currentHours % 100;
                          return (
                            <>
                              <p className="text-sm text-gray-600 mb-3">Fortschritt: {currentHours} Trails absolviert im Expert-Status</p>
                              <div className="flex flex-wrap gap-2">
                                {Array.from({ length: fullMilestones }).map((_, i) => (<HundredHourMilestoneBadge key={`milestone-${i}`} milestoneNumber={i + 1} />))}
                                {Array.from({ length: remainingHours }).map((_, i) => (<TrainingPawIcon key={`paw-${i}`} filled={true} />))}
                              </div>
                            </>
                          );
                        })()
                      ) : (
                        <>
                          <p className="text-sm text-gray-600 mb-3">Fortschritt: {section.completedHours} / {section.requiredHours} Trails</p>
                          <div className="flex flex-wrap gap-2">
                            {Array.from({ length: section.completedHours }).map((_, i) => (<TrainingPawIcon key={i} filled={true} />))}
                            {Array.from({ length: section.requiredHours - section.completedHours }).map((_, i) => (<TrainingPawIcon key={`empty-${i}`} filled={false} />))}
                          </div>
                        </>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </Card>
        </div>
        <div className="lg:col-span-1 space-y-6">
          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Konto-Übersicht</h2>
            <div className="space-y-2 text-gray-700">
              <div className="flex justify-between"><span>Guthaben</span><span className="font-semibold">{customer.balance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}</span></div>
              <div className="flex justify-between"><span>Transaktionen</span><span className="font-semibold">{customer.totalTransactions}</span></div>
              <div className="flex justify-between"><span>Erstellt am</span><span className="font-semibold">{customer.createdAt}</span></div>
              <div className="flex justify-between"><span>Kunden-ID</span><span className="font-semibold">{customer.id}</span></div>
            </div>
          </Card>

          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Transaktionshistorie</h2>
            <div className="space-y-3 max-h-96 overflow-y-auto custom-scrollbar">
              {customerTransactions.length === 0 ? (
                <p className="text-gray-500 text-center py-4">Für diesen Kunden sind noch keine Transaktionen vorhanden.</p>
              ) : (
                customerTransactions.slice(0, 5).map((transaction) => { // Display only the first 5 transactions here
                  const isRecharge = transaction.type === 'recharge';
                  const Icon = isRecharge ? ArrowUpCircleIcon : ArrowDownCircleIcon;
                  const iconColor = isRecharge ? 'text-green-500' : 'text-red-500';
                  const amountColor = isRecharge ? 'text-green-700' : 'text-red-700';
                  const amountSign = isRecharge ? '+' : '-';

                  return (
                    <div key={transaction.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                      <div className="flex items-center">
                        <Icon className={`h-8 w-8 mr-3 flex-shrink-0 ${iconColor}`} />
                        <div>
                          <p className="font-medium text-gray-900">{transaction.description}</p>
                          <p className="text-sm text-gray-500">{transaction.date} &bull; {transaction.employee}</p>
                        </div>
                      </div>
                      <p className={`font-semibold text-lg whitespace-nowrap ${amountColor}`}>
                        {amountSign}{Math.abs(transaction.amount).toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
                      </p>
                    </div>
                  );
                })
              )}
            </div>
          </Card>

          <Card className="text-center">
            <h2 className="text-xl font-semibold text-gray-900 mb-4">QR-Code</h2>
            <QRCodeDisplay dataUrl={customer.qrCodeData} className="mb-3" />
            <p className="text-sm text-gray-600">Scannen, um diese Kundenkarte schnell aufzurufen.</p>
          </Card>
        </div>
      </div>
      <TransactionConfirmationModal
        isOpen={showConfirmationModal}
        onClose={() => setShowConfirmationModal(false)}
        onConfirm={handleConfirmTransaction}
        data={transactionData}
      />
      <TransactionTypeSelectionModal
        isOpen={showTransactionTypeModal}
        onClose={() => setShowTransactionTypeModal(false)}
        onSelectType={handleSelectTransactionType}
      />
      <CustomerFormModal
        isOpen={isEditModalOpen}
        onClose={() => setIsEditModalOpen(false)}
        onSubmit={handleUpdateStammdaten}
        customerToEdit={customer}
      />
      <TransactionHistoryModal
        isOpen={isTransactionHistoryModalOpen}
        onClose={() => setIsTransactionHistoryModalOpen(false)}
        transactions={customerTransactions}
        customerName={`${customer.firstName} ${customer.lastName}`}
      />
    </div>
  );
};

export default CustomerDetails;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import Card from '../components/Card';
import Avatar from '../components/Avatar';
import Button from '../components/Button';
import Input from '../components/Input';
import QRCodeDisplay from '../components/QRCodeDisplay';
import TransactionConfirmationModal from '../components/TransactionConfirmationModal';
import TransactionTypeSelectionModal from '../components/TransactionTypeSelectionModal';
import CustomerFormModal from '../components/CustomerFormModal';
import TransactionHistoryModal from '../components/TransactionHistoryModal'; // Import the new modal
import {
  ArrowLeftIcon,
  HeartIcon,
  CreditCardIcon,
  MailIcon,
  PhoneIcon,
  AwardIcon,
  UploadIcon,
  UserIcon,
  ChevronDownIcon,
  EditIcon,
  SaveIcon,
  ArrowUpCircleIcon,
  ArrowDownCircleIcon,
} from '../components/Icons';
import { CURRENT_EMPLOYEE, REFERENCE_DATE } from '../constants';
import { Customer, TrainingLevelEnum, TransactionConfirmationData, Transaction, User, UserRoleEnum, NewCustomerData } from '../types';

interface TrainingHourCircleProps {
  filled: boolean;
  className?: string;
}

const TrainingPawIcon: React.FC<TrainingHourCircleProps> = ({ filled, className = '' }) => (
  <div
    className={`flex items-center justify-center h-16 w-16 rounded-full border
      ${filled ? 'bg-gray-100 border-gray-300' : 'bg-gray-50 border-gray-200'}
      ${className}`}
  >
    <img
      src="https://hs-bw.com/wp-content/uploads/2025/12/Suchund-Icon.png"
      alt="Paw Icon"
      className={`h-10 w-10 object-contain ${!filled ? 'grayscale opacity-50' : ''}`}
    />
  </div>
);

interface HundredHourMilestoneBadgeProps {
  milestoneNumber: number;
}

const HundredHourMilestoneBadge: React.FC<HundredHourMilestoneBadgeProps> = ({ milestoneNumber }) => {
  const baseClasses = "flex flex-col items-center justify-center h-32 w-32 p-2 rounded-lg text-center shadow-md";
  let specificClasses = "";
  let textColor = "text-amber-800";

  switch (milestoneNumber) {
    case 1:
      specificClasses = "bg-amber-100 border border-amber-300";
      break;
    case 2:
      specificClasses = "bg-orange-100 border border-orange-300 shadow-lg";
      textColor = "text-orange-800";
      break;
    case 3:
      specificClasses = "bg-red-100 border border-red-300 shadow-xl";
      textColor = "text-red-800";
      break;
    case 4:
      specificClasses = "bg-purple-100 border border-purple-300 shadow-2xl";
      textColor = "text-purple-800";
      break;
    case 5:
      specificClasses = "bg-blue-100 border border-blue-300 shadow-2xl";
      textColor = "text-blue-800";
      break;
    default:
      specificClasses = "bg-gray-100 border border-gray-300";
      textColor = "text-gray-800";
      break;
  }

  return (
    <div className={`${baseClasses} ${specificClasses}`}>
      <img
        src="https://hs-bw.com/wp-content/uploads/2025/12/Suchund-Icon.png"
        alt={`${milestoneNumber * 100} Trails gemeistert`}
        className="h-20 w-20 object-contain filter drop-shadow-sm"
      />
      <p className={`text-sm font-bold ${textColor} mt-1`}>{milestoneNumber * 100} Trails gemeistert!</p>
    </div>
  );
};

interface CustomerDetailsProps {
  customers: Customer[];
  transactions: Transaction[];
  onUpdateCustomer: (updatedCustomer: Customer) => void;
  onAddTransaction: (newTransaction: Transaction) => void;
  currentUser: User;
}

const CustomerDetails: React.FC<CustomerDetailsProps> = ({
  customers,
  transactions,
  onUpdateCustomer,
  onAddTransaction,
  currentUser,
}) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [showConfirmationModal, setShowConfirmationModal] = useState(false);
  const [showTransactionTypeModal, setShowTransactionTypeModal] = useState(false);
  const [isTransactionHistoryModalOpen, setIsTransactionHistoryModalOpen] = useState(false);
  const [transactionData, setTransactionData] = useState<TransactionConfirmationData | null>(null);
  const [customer, setCustomer] = useState<Customer | null>(null);
  const [isLoadingCustomer, setIsLoadingCustomer] = useState(true);
  const [isEditMode, setIsEditMode] = useState(false);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editableData, setEditableData] = useState({
    phone: '',
    dogName: '',
    chipNumber: '',
  });

  useEffect(() => {
    setIsLoadingCustomer(true);
    if (id) {
      const foundCustomer = customers.find((c) => c.id === id);
      setCustomer(foundCustomer || null);

      if (foundCustomer) {
        setEditableData({
          phone: foundCustomer.phone,
          dogName: foundCustomer.dogName,
          chipNumber: foundCustomer.chipNumber,
        });
      }
    } else {
      setCustomer(null);
    }
    setIsLoadingCustomer(false);
  }, [id, customers]);

  // Authorization Effect: Redirect if a customer tries to access another customer's page
  useEffect(() => {
    if (currentUser.role === UserRoleEnum.KUNDE && currentUser.associatedCustomerId && id !== currentUser.associatedCustomerId) {
        navigate(`/customers/${currentUser.associatedCustomerId}`, { replace: true });
    }
  }, [currentUser, id, navigate]);

  const [expandedSections, setExpandedSections] = useState<Record<number, boolean>>({});

  useEffect(() => {
    if (customer) {
      setExpandedSections(prev => {
        const newExpanded = { ...prev };
        customer.trainingProgress.forEach(section => {
          if (newExpanded[section.id] === undefined) {
            newExpanded[section.id] = false;
          }
        });
        return newExpanded;
      });
    }
  }, [customer]);

  // Filter and sort transactions for the current customer
  const customerTransactions = transactions
    .filter(t => t.customerId === id)
    .sort((a, b) => {
      const dateA = new Date(a.date.split('.').reverse().join('-'));
      const dateB = new Date(b.date.split('.').reverse().join('-'));
      return dateB.getTime() - dateA.getTime();
    });

  if (!id) {
    return (
      <div className="p-8 text-center text-red-600">
        Keine Kunden-ID in der URL gefunden.
        <Button variant="primary" onClick={() => navigate('/customers')} className="mt-4">
          Zurück zur Kundenliste
        </Button>
      </div>
    );
  }

  if (isLoadingCustomer) {
    return <div className="p-8 text-center text-gray-600">Lade Kundendaten...</div>;
  }

  if (!customer) {
    return (
      <div className="p-8 text-center text-gray-600">
        Kunde mit ID "{id}" nicht gefunden.
        <Button variant="primary" onClick={() => navigate('/customers')} className="mt-4">
          Zurück zur Kundenliste
        </Button>
      </div>
    );
  }

  const handleOpenConfirmationModal = (amount: number, type: 'Aufladung' | 'Abbuchung', description?: string) => {
    const oldBalance = customer.balance;
    const newBalance = type === 'Aufladung' ? oldBalance + amount : oldBalance - amount;
    setTransactionData({
      customerId: customer.id,
      customerName: `${customer.firstName} ${customer.lastName}`,
      employee: CURRENT_EMPLOYEE,
      transactionType: type,
      amount: amount,
      oldBalance: oldBalance,
      newBalance: newBalance,
      description: description,
    });
    setShowConfirmationModal(true);
  };

  const handleConfirmTransaction = () => {
    if (!transactionData || !customer) return;

    let finalUpdatedCustomer: Customer = { ...customer };
    finalUpdatedCustomer.balance = transactionData.newBalance;
    finalUpdatedCustomer.totalTransactions = customer.totalTransactions + 1;

    const isRecharge = transactionData.transactionType === 'Aufladung';
    if (!isRecharge && transactionData.description === 'Trails' && transactionData.amount === 18) {
      const currentTrainingProgress = [...customer.trainingProgress];
      let customerOverallLevel = finalUpdatedCustomer.level;
      const currentLevelIndex = currentTrainingProgress.findIndex(s => s.status === 'Aktuell');

      if (currentLevelIndex !== -1) {
        const currentSection = { ...currentTrainingProgress[currentLevelIndex] };
        if (currentSection.name === TrainingLevelEnum.EXPERT) {
          if (currentSection.completedHours < 500) {
            currentSection.completedHours += 1;
            currentTrainingProgress[currentLevelIndex] = currentSection;
          }
        } else if (currentSection.completedHours < currentSection.requiredHours) {
          currentSection.completedHours += 1;
          if (currentSection.completedHours === currentSection.requiredHours) {
            currentSection.status = 'Abgeschlossen';
            const nextLevelIndex = currentLevelIndex + 1;
            if (nextLevelIndex < currentTrainingProgress.length) {
              const nextSection = { ...currentTrainingProgress[nextLevelIndex] };
              nextSection.status = 'Aktuell';
              customerOverallLevel = nextSection.name;
              currentTrainingProgress[nextLevelIndex] = nextSection;
            }
          }
          currentTrainingProgress[currentLevelIndex] = currentSection;
        }
        finalUpdatedCustomer.trainingProgress = currentTrainingProgress;
        finalUpdatedCustomer.level = customerOverallLevel;
      }
    }

    onUpdateCustomer(finalUpdatedCustomer);

    const newTransaction: Transaction = {
      id: `trx-${transactions.length + 1}-${Date.now()}`,
      customerId: customer.id,
      type: transactionData.transactionType === 'Aufladung' ? 'recharge' : 'debit',
      description: transactionData.description || (transactionData.transactionType === 'Aufladung' ? 'Aufladung' : 'Trails'),
      amount: transactionData.amount,
      date: REFERENCE_DATE.toLocaleDateString('de-DE'),
      employee: CURRENT_EMPLOYEE,
    };
    onAddTransaction(newTransaction);
    setShowConfirmationModal(false);
    setTransactionData(null);
  };

  const handleSelectTransactionType = (type: 'Aufladung' | 'Abbuchung') => {
    setShowTransactionTypeModal(false);
    let defaultAmount = type === 'Aufladung' ? 215 : 18;
    let description = type === 'Aufladung' ? 'Guthabenaufladung' : 'Trails';
    handleOpenConfirmationModal(defaultAmount, type, description);
  };

  const handleToggleEditMode = () => {
    if (!isEditMode) {
      setEditableData({
        phone: customer.phone,
        dogName: customer.dogName,
        chipNumber: customer.chipNumber,
      });
    }
    setIsEditMode(!isEditMode);
  };

  const handleCancelEdit = () => {
    setIsEditMode(false);
  };

  const handleSaveChanges = () => {
    const updatedCustomer = {
      ...customer,
      phone: editableData.phone,
      dogName: editableData.dogName,
      chipNumber: editableData.chipNumber,
    };
    onUpdateCustomer(updatedCustomer);
    setIsEditMode(false);
  };

  const handleUpdateStammdaten = (data: NewCustomerData) => {
    if (!customer) return;
    const updatedCustomer = { ...customer, ...data };
    onUpdateCustomer(updatedCustomer);
    setIsEditModalOpen(false);
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { id, value } = e.target;
    setEditableData(prev => ({ ...prev, [id]: value }));
  };

  const getStatusClasses = (status: string) => {
    switch (status) {
      case 'Aktuell': return 'bg-green-100 text-green-800';
      case 'Gesperrt': return 'bg-red-100 text-red-800';
      case 'Abgeschlossen': return 'bg-blue-100 text-blue-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const DataRow: React.FC<{ Icon: React.ElementType; label: string; value: string | number }> = ({ Icon, label, value }) => (
    <div>
      <div className="flex items-center text-gray-500 mb-1">
        <Icon className="h-4 w-4 mr-2" />
        <span className="text-sm font-medium">{label}</span>
      </div>
      <p className="font-semibold text-gray-900 ml-6">{value}</p>
    </div>
  );

  const toggleSection = (sectionId: number) => {
    setExpandedSections(prev => ({ ...prev, [sectionId]: !prev[sectionId] }));
  };

  const getLevelSummaryCardColors = (level: TrainingLevelEnum) => {
    switch (level) {
      case TrainingLevelEnum.EINSTEIGER: return { bg: 'bg-fuchsia-50', text: 'text-fuchsia-700', icon: 'text-fuchsia-700' };
      case TrainingLevelEnum.GRUNDLAGEN: return { bg: 'bg-lime-50', text: 'text-lime-700', icon: 'text-lime-700' };
      case TrainingLevelEnum.FORTGESCHRITTENE: return { bg: 'bg-sky-50', text: 'text-sky-700', icon: 'text-sky-700' };
      case TrainingLevelEnum.MASTERCLASS: return { bg: 'bg-amber-50', text: 'text-amber-700', icon: 'text-amber-700' };
      case TrainingLevelEnum.EXPERT: return { bg: 'bg-indigo-50', text: 'text-indigo-700', icon: 'text-indigo-700' };
      default: return { bg: 'bg-gray-50', text: 'text-gray-700', icon: 'text-gray-700' };
    }
  };

  const levelSummaryColors = getLevelSummaryCardColors(customer.level);
  const canPerformActions = currentUser.role === UserRoleEnum.ADMIN || currentUser.role === UserRoleEnum.MITARBEITER;
  const isCustomerViewing = currentUser.role === UserRoleEnum.KUNDE;

  return (
    <div className="p-6 md:p-8 lg:p-10 min-h-screen">
      <div className="flex items-center justify-between mb-6 flex-wrap gap-4">
        <div className="flex items-center">
          {!isCustomerViewing && (
            <button onClick={() => navigate('/customers')} className="text-gray-500 hover:text-gray-700 mr-4">
              <ArrowLeftIcon className="h-6 w-6" />
            </button>
          )}
          <h1 className="text-2xl font-bold text-gray-900 flex items-center">
            {customer.firstName} {customer.lastName}
            <span className="text-gray-500 font-normal text-base ml-2">
              {isCustomerViewing ? "Meine Übersicht" : "Kundendetails & Übersicht"}
            </span>
          </h1>
        </div>

        {isEditMode ? (
          <div className="flex space-x-3">
            <Button variant="outline" onClick={handleCancelEdit}>Abbrechen</Button>
            <Button variant="success" icon={SaveIcon} onClick={handleSaveChanges}>Speichern</Button>
          </div>
        ) : (
          <div className="flex space-x-3">
            {canPerformActions && (
              <>
                <Button variant="outline" onClick={() => setIsEditModalOpen(true)}>Stammdaten</Button>
                <Button variant="success" onClick={() => setShowTransactionTypeModal(true)}>Transaktionen</Button>
              </>
            )}
            {isCustomerViewing && (
              <Button variant="primary" icon={EditIcon} onClick={handleToggleEditMode}>Meine Daten bearbeiten</Button>
            )}
          </div>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-6">
          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Persönliche Daten</h2>
            <div className="flex items-start">
              <Avatar initials={customer.avatarInitials} color={customer.avatarColor} size="lg" className="mr-6 flex-shrink-0" />
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-12 gap-y-6 flex-grow">
                <DataRow Icon={UserIcon} label="Vorname" value={customer.firstName} />
                <DataRow Icon={UserIcon} label="Nachname" value={customer.lastName} />
                <DataRow Icon={MailIcon} label="E-Mail" value={customer.email} />
                {isEditMode ? (
                  <Input id="phone" label="Telefon" value={editableData.phone} onChange={handleInputChange} />
                ) : (
                  <DataRow Icon={PhoneIcon} label="Telefon" value={customer.phone} />
                )}
                {isEditMode ? (
                  <Input id="dogName" label="Hund" value={editableData.dogName} onChange={handleInputChange} />
                ) : (
                  <DataRow Icon={HeartIcon} label="Hund" value={customer.dogName} />
                )}
                {isEditMode ? (
                  <Input id="chipNumber" label="Chipnummer" value={editableData.chipNumber} onChange={handleInputChange} />
                ) : (
                  <DataRow Icon={CreditCardIcon} label="Chipnummer" value={customer.chipNumber} />
                )}
              </div>
            </div>
          </Card>

          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Übersicht</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="bg-green-50 p-4 rounded-lg flex flex-col justify-center items-center text-center">
                <p className="text-sm text-gray-600 mb-1">Aktuelles Guthaben</p>
                <p className="text-2xl font-bold text-green-700">{customer.balance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}</p>
              </div>
              <button
                onClick={() => setIsTransactionHistoryModalOpen(true)}
                className="bg-blue-50 p-4 rounded-lg flex flex-col justify-center items-center text-center w-full hover:bg-blue-100 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 transition-colors"
              >
                <p className="text-sm text-gray-600 mb-1">Transaktionen gesamt</p>
                <p className="text-2xl font-bold text-blue-700">{customer.totalTransactions}</p>
              </button>
              <div className={`${levelSummaryColors.bg} p-4 rounded-lg flex flex-col justify-center items-center text-center`}>
                <p className="text-sm text-gray-600 mb-1">Level</p>
                <div className="flex items-center mt-2">
                  <AwardIcon className={`h-10 w-10 mr-2 ${levelSummaryColors.icon}`} />
                  <p className={`text-2xl font-bold ${levelSummaryColors.text}`}>{customer.level}</p>
                </div>
              </div>
            </div>
          </Card>

          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Ausbildungsfortschritt</h2>
            <div className="space-y-6">
              {customer.trainingProgress.map((section) => {
                let headerBgClass = 'bg-gray-50';
                let levelCircleBgClass = 'bg-gray-400';

                switch (section.name) {
                  case TrainingLevelEnum.EINSTEIGER: headerBgClass = 'bg-fuchsia-50'; break;
                  case TrainingLevelEnum.GRUNDLAGEN: headerBgClass = 'bg-lime-50'; break;
                  case TrainingLevelEnum.FORTGESCHRITTENE: headerBgClass = 'bg-sky-50'; break;
                  case TrainingLevelEnum.MASTERCLASS: headerBgClass = 'bg-amber-50'; break;
                  case TrainingLevelEnum.EXPERT: headerBgClass = 'bg-indigo-50'; break;
                }
                switch (section.name) {
                  case TrainingLevelEnum.EINSTEIGER: levelCircleBgClass = 'bg-fuchsia-500'; break;
                  case TrainingLevelEnum.GRUNDLAGEN: levelCircleBgClass = 'bg-lime-500'; break;
                  case TrainingLevelEnum.FORTGESCHRITTENE: levelCircleBgClass = 'bg-sky-500'; break;
                  case TrainingLevelEnum.MASTERCLASS: levelCircleBgClass = 'bg-amber-500'; break;
                  case TrainingLevelEnum.EXPERT: levelCircleBgClass = 'bg-indigo-500'; break;
                }

                const isExpanded = expandedSections[section.id];
                return (
                  <div key={section.id} className="rounded-lg overflow-hidden border border-gray-200 shadow-sm">
                    <button
                      className={`p-4 flex items-center justify-between w-full text-left ${headerBgClass}`}
                      onClick={() => toggleSection(section.id)}
                      aria-expanded={isExpanded}
                      aria-controls={`section-content-${section.id}`}
                    >
                      <h3 className="text-lg font-medium text-gray-900 flex items-center">
                        <span className={`flex items-center justify-center h-8 w-8 rounded-full text-white font-bold text-base mr-3 ${levelCircleBgClass}`}>{section.id}</span>
                        {section.name}
                      </h3>
                      <div className="flex items-center">
                        <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${getStatusClasses(section.status)} mr-2`}>{section.status}</span>
                        <ChevronDownIcon className={`h-5 w-5 text-gray-500 transition-transform duration-200 ${isExpanded ? 'rotate-180' : ''}`} />
                      </div>
                    </button>
                    <div id={`section-content-${section.id}`} className={`${isExpanded ? 'block' : 'hidden'} p-4 bg-white border-t border-gray-200`}>
                      {section.name === TrainingLevelEnum.EXPERT ? (
                        (() => {
                          const currentHours = section.completedHours;
                          const fullMilestones = Math.floor(currentHours / 100);
                          const remainingHours = currentHours % 100;
                          return (
                            <>
                              <p className="text-sm text-gray-600 mb-3">Fortschritt: {currentHours} Trails absolviert im Expert-Status</p>
                              <div className="flex flex-wrap gap-2">
                                {Array.from({ length: fullMilestones }).map((_, i) => (<HundredHourMilestoneBadge key={`milestone-${i}`} milestoneNumber={i + 1} />))}
                                {Array.from({ length: remainingHours }).map((_, i) => (<TrainingPawIcon key={`paw-${i}`} filled={true} />))}
                              </div>
                            </>
                          );
                        })()
                      ) : (
                        <>
                          <p className="text-sm text-gray-600 mb-3">Fortschritt: {section.completedHours} / {section.requiredHours} Trails</p>
                          <div className="flex flex-wrap gap-2">
                            {Array.from({ length: section.completedHours }).map((_, i) => (<TrainingPawIcon key={i} filled={true} />))}
                            {Array.from({ length: section.requiredHours - section.completedHours }).map((_, i) => (<TrainingPawIcon key={`empty-${i}`} filled={false} />))}
                          </div>
                        </>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </Card>
        </div>
        <div className="lg:col-span-1 space-y-6">
          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Konto-Übersicht</h2>
            <div className="space-y-2 text-gray-700">
              <div className="flex justify-between"><span>Guthaben</span><span className="font-semibold">{customer.balance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}</span></div>
              <div className="flex justify-between"><span>Transaktionen</span><span className="font-semibold">{customer.totalTransactions}</span></div>
              <div className="flex justify-between"><span>Erstellt am</span><span className="font-semibold">{customer.createdAt}</span></div>
              <div className="flex justify-between"><span>Kunden-ID</span><span className="font-semibold">{customer.id}</span></div>
            </div>
          </Card>

          <Card className="text-center">
            <h2 className="text-xl font-semibold text-gray-900 mb-4">QR-Code</h2>
            <QRCodeDisplay dataUrl={customer.qrCodeData} className="mb-3" />
            <p className="text-sm text-gray-600">Scannen, um diese Kundenkarte schnell aufzurufen.</p>
          </Card>
        </div>
      </div>
      <TransactionConfirmationModal
        isOpen={showConfirmationModal}
        onClose={() => setShowConfirmationModal(false)}
        onConfirm={handleConfirmTransaction}
        data={transactionData}
      />
      <TransactionTypeSelectionModal
        isOpen={showTransactionTypeModal}
        onClose={() => setShowTransactionTypeModal(false)}
        onSelectType={handleSelectTransactionType}
      />
      <CustomerFormModal
        isOpen={isEditModalOpen}
        onClose={() => setIsEditModalOpen(false)}
        onSubmit={handleUpdateStammdaten}
        customerToEdit={customer}
      />
      <TransactionHistoryModal
        isOpen={isTransactionHistoryModalOpen}
        onClose={() => setIsTransactionHistoryModalOpen(false)}
        transactions={customerTransactions}
        customerName={`${customer.firstName} ${customer.lastName}`}
      />
    </div>
  );
};

export default CustomerDetails;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import Card from '../components/Card';
import Avatar from '../components/Avatar';
import Button from '../components/Button';
import Input from '../components/Input';
import QRCodeDisplay from '../components/QRCodeDisplay';
import TransactionConfirmationModal from '../components/TransactionConfirmationModal';
import TransactionTypeSelectionModal from '../components/TransactionTypeSelectionModal';
import CustomerFormModal from '../components/CustomerFormModal';
import TransactionHistoryModal from '../components/TransactionHistoryModal'; // Import the new modal
import {
  ArrowLeftIcon,
  HeartIcon,
  CreditCardIcon,
  MailIcon,
  PhoneIcon,
  AwardIcon,
  UploadIcon,
  UserIcon,
  ChevronDownIcon,
  EditIcon,
  SaveIcon,
  ArrowUpCircleIcon,
  ArrowDownCircleIcon,
} from '../components/Icons';
import { CURRENT_EMPLOYEE, REFERENCE_DATE } from '../constants';
import { Customer, TrainingLevelEnum, TransactionConfirmationData, Transaction, User, UserRoleEnum, NewCustomerData } from '../types';

interface TrainingHourCircleProps {
  filled: boolean;
  className?: string;
}

const TrainingPawIcon: React.FC<TrainingHourCircleProps> = ({ filled, className = '' }) => (
  <div
    className={`flex items-center justify-center h-16 w-16 rounded-full border
      ${filled ? 'bg-gray-100 border-gray-300' : 'bg-gray-50 border-gray-200'}
      ${className}`}
  >
    <img
      src="https://hs-bw.com/wp-content/uploads/2025/12/Suchund-Icon.png"
      alt="Paw Icon"
      className={`h-10 w-10 object-contain ${!filled ? 'grayscale opacity-50' : ''}`}
    />
  </div>
);

interface HundredHourMilestoneBadgeProps {
  milestoneNumber: number;
}

const HundredHourMilestoneBadge: React.FC<HundredHourMilestoneBadgeProps> = ({ milestoneNumber }) => {
  const baseClasses = "flex flex-col items-center justify-center h-32 w-32 p-2 rounded-lg text-center shadow-md";
  let specificClasses = "";
  let textColor = "text-amber-800";

  switch (milestoneNumber) {
    case 1:
      specificClasses = "bg-amber-100 border border-amber-300";
      break;
    case 2:
      specificClasses = "bg-orange-100 border border-orange-300 shadow-lg";
      textColor = "text-orange-800";
      break;
    case 3:
      specificClasses = "bg-red-100 border border-red-300 shadow-xl";
      textColor = "text-red-800";
      break;
    case 4:
      specificClasses = "bg-purple-100 border border-purple-300 shadow-2xl";
      textColor = "text-purple-800";
      break;
    case 5:
      specificClasses = "bg-blue-100 border border-blue-300 shadow-2xl";
      textColor = "text-blue-800";
      break;
    default:
      specificClasses = "bg-gray-100 border border-gray-300";
      textColor = "text-gray-800";
      break;
  }

  return (
    <div className={`${baseClasses} ${specificClasses}`}>
      <img
        src="https://hs-bw.com/wp-content/uploads/2025/12/Suchund-Icon.png"
        alt={`${milestoneNumber * 100} Trails gemeistert`}
        className="h-20 w-20 object-contain filter drop-shadow-sm"
      />
      <p className={`text-sm font-bold ${textColor} mt-1`}>{milestoneNumber * 100} Trails gemeistert!</p>
    </div>
  );
};

interface CustomerDetailsProps {
  customers: Customer[];
  transactions: Transaction[];
  onUpdateCustomer: (updatedCustomer: Customer) => void;
  onAddTransaction: (newTransaction: Transaction) => void;
  currentUser: User;
}

const CustomerDetails: React.FC<CustomerDetailsProps> = ({
  customers,
  transactions,
  onUpdateCustomer,
  onAddTransaction,
  currentUser,
}) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [showConfirmationModal, setShowConfirmationModal] = useState(false);
  const [showTransactionTypeModal, setShowTransactionTypeModal] = useState(false);
  const [isTransactionHistoryModalOpen, setIsTransactionHistoryModalOpen] = useState(false);
  const [transactionData, setTransactionData] = useState<TransactionConfirmationData | null>(null);
  const [customer, setCustomer] = useState<Customer | null>(null);
  const [isLoadingCustomer, setIsLoadingCustomer] = useState(true);
  const [isEditMode, setIsEditMode] = useState(false);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editableData, setEditableData] = useState({
    phone: '',
    dogName: '',
    chipNumber: '',
  });

  useEffect(() => {
    setIsLoadingCustomer(true);
    if (id) {
      const foundCustomer = customers.find((c) => c.id === id);
      setCustomer(foundCustomer || null);

      if (foundCustomer) {
        setEditableData({
          phone: foundCustomer.phone,
          dogName: foundCustomer.dogName,
          chipNumber: foundCustomer.chipNumber,
        });
      }
    } else {
      setCustomer(null);
    }
    setIsLoadingCustomer(false);
  }, [id, customers]);

  // Authorization Effect: Redirect if a customer tries to access another customer's page
  useEffect(() => {
    if (currentUser.role === UserRoleEnum.KUNDE && currentUser.associatedCustomerId && id !== currentUser.associatedCustomerId) {
        navigate(`/customers/${currentUser.associatedCustomerId}`, { replace: true });
    }
  }, [currentUser, id, navigate]);

  const [expandedSections, setExpandedSections] = useState<Record<number, boolean>>({});

  useEffect(() => {
    if (customer) {
      setExpandedSections(prev => {
        const newExpanded = { ...prev };
        customer.trainingProgress.forEach(section => {
          if (newExpanded[section.id] === undefined) {
            newExpanded[section.id] = false;
          }
        });
        return newExpanded;
      });
    }
  }, [customer]);

  // Filter and sort transactions for the current customer
  const customerTransactions = transactions
    .filter(t => t.customerId === id)
    .sort((a, b) => {
      const dateA = new Date(a.date.split('.').reverse().join('-'));
      const dateB = new Date(b.date.split('.').reverse().join('-'));
      return dateB.getTime() - dateA.getTime();
    });

  if (!id) {
    return (
      <div className="p-8 text-center text-red-600">
        Keine Kunden-ID in der URL gefunden.
        <Button variant="primary" onClick={() => navigate('/customers')} className="mt-4">
          Zurück zur Kundenliste
        </Button>
      </div>
    );
  }

  if (isLoadingCustomer) {
    return <div className="p-8 text-center text-gray-600">Lade Kundendaten...</div>;
  }

  if (!customer) {
    return (
      <div className="p-8 text-center text-gray-600">
        Kunde mit ID "{id}" nicht gefunden.
        <Button variant="primary" onClick={() => navigate('/customers')} className="mt-4">
          Zurück zur Kundenliste
        </Button>
      </div>
    );
  }

  const handleOpenConfirmationModal = (amount: number, type: 'Aufladung' | 'Abbuchung', description?: string) => {
    const oldBalance = customer.balance;
    const newBalance = type === 'Aufladung' ? oldBalance + amount : oldBalance - amount;
    setTransactionData({
      customerId: customer.id,
      customerName: `${customer.firstName} ${customer.lastName}`,
      employee: CURRENT_EMPLOYEE,
      transactionType: type,
      amount: amount,
      oldBalance: oldBalance,
      newBalance: newBalance,
      description: description,
    });
    setShowConfirmationModal(true);
  };

  const handleConfirmTransaction = () => {
    if (!transactionData || !customer) return;

    let finalUpdatedCustomer: Customer = { ...customer };
    finalUpdatedCustomer.balance = transactionData.newBalance;
    finalUpdatedCustomer.totalTransactions = customer.totalTransactions + 1;

    const isRecharge = transactionData.transactionType === 'Aufladung';
    if (!isRecharge && transactionData.description === 'Trails' && transactionData.amount === 18) {
      const currentTrainingProgress = [...customer.trainingProgress];
      let customerOverallLevel = finalUpdatedCustomer.level;
      const currentLevelIndex = currentTrainingProgress.findIndex(s => s.status === 'Aktuell');

      if (currentLevelIndex !== -1) {
        const currentSection = { ...currentTrainingProgress[currentLevelIndex] };
        if (currentSection.name === TrainingLevelEnum.EXPERT) {
          if (currentSection.completedHours < 500) {
            currentSection.completedHours += 1;
            currentTrainingProgress[currentLevelIndex] = currentSection;
          }
        } else if (currentSection.completedHours < currentSection.requiredHours) {
          currentSection.completedHours += 1;
          if (currentSection.completedHours === currentSection.requiredHours) {
            currentSection.status = 'Abgeschlossen';
            const nextLevelIndex = currentLevelIndex + 1;
            if (nextLevelIndex < currentTrainingProgress.length) {
              const nextSection = { ...currentTrainingProgress[nextLevelIndex] };
              nextSection.status = 'Aktuell';
              customerOverallLevel = nextSection.name;
              currentTrainingProgress[nextLevelIndex] = nextSection;
            }
          }
          currentTrainingProgress[currentLevelIndex] = currentSection;
        }
        finalUpdatedCustomer.trainingProgress = currentTrainingProgress;
        finalUpdatedCustomer.level = customerOverallLevel;
      }
    }

    onUpdateCustomer(finalUpdatedCustomer);

    const newTransaction: Transaction = {
      id: `trx-${transactions.length + 1}-${Date.now()}`,
      customerId: customer.id,
      type: transactionData.transactionType === 'Aufladung' ? 'recharge' : 'debit',
      description: transactionData.description || (transactionData.transactionType === 'Aufladung' ? 'Aufladung' : 'Trails'),
      amount: transactionData.amount,
      date: REFERENCE_DATE.toLocaleDateString('de-DE'),
      employee: CURRENT_EMPLOYEE,
    };
    onAddTransaction(newTransaction);
    setShowConfirmationModal(false);
    setTransactionData(null);
  };

  const handleSelectTransactionType = (type: 'Aufladung' | 'Abbuchung') => {
    setShowTransactionTypeModal(false);
    let defaultAmount = type === 'Aufladung' ? 215 : 18;
    let description = type === 'Aufladung' ? 'Guthabenaufladung' : 'Trails';
    handleOpenConfirmationModal(defaultAmount, type, description);
  };

  const handleToggleEditMode = () => {
    if (!isEditMode) {
      setEditableData({
        phone: customer.phone,
        dogName: customer.dogName,
        chipNumber: customer.chipNumber,
      });
    }
    setIsEditMode(!isEditMode);
  };

  const handleCancelEdit = () => {
    setIsEditMode(false);
  };

  const handleSaveChanges = () => {
    const updatedCustomer = {
      ...customer,
      phone: editableData.phone,
      dogName: editableData.dogName,
      chipNumber: editableData.chipNumber,
    };
    onUpdateCustomer(updatedCustomer);
    setIsEditMode(false);
  };

  const handleUpdateStammdaten = (data: NewCustomerData) => {
    if (!customer) return;
    const updatedCustomer = { ...customer, ...data };
    onUpdateCustomer(updatedCustomer);
    setIsEditModalOpen(false);
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { id, value } = e.target;
    setEditableData(prev => ({ ...prev, [id]: value }));
  };

  const getStatusClasses = (status: string) => {
    switch (status) {
      case 'Aktuell': return 'bg-green-100 text-green-800';
      case 'Gesperrt': return 'bg-red-100 text-red-800';
      case 'Abgeschlossen': return 'bg-blue-100 text-blue-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const DataRow: React.FC<{ Icon: React.ElementType; label: string; value: string | number }> = ({ Icon, label, value }) => (
    <div>
      <div className="flex items-center text-gray-500 mb-1">
        <Icon className="h-4 w-4 mr-2" />
        <span className="text-sm font-medium">{label}</span>
      </div>
      <p className="font-semibold text-gray-900 ml-6">{value}</p>
    </div>
  );

  const toggleSection = (sectionId: number) => {
    setExpandedSections(prev => ({ ...prev, [sectionId]: !prev[sectionId] }));
  };

  const getLevelSummaryCardColors = (level: TrainingLevelEnum) => {
    switch (level) {
      case TrainingLevelEnum.EINSTEIGER: return { bg: 'bg-fuchsia-50', text: 'text-fuchsia-700', icon: 'text-fuchsia-700' };
      case TrainingLevelEnum.GRUNDLAGEN: return { bg: 'bg-lime-50', text: 'text-lime-700', icon: 'text-lime-700' };
      case TrainingLevelEnum.FORTGESCHRITTENE: return { bg: 'bg-sky-50', text: 'text-sky-700', icon: 'text-sky-700' };
      case TrainingLevelEnum.MASTERCLASS: return { bg: 'bg-amber-50', text: 'text-amber-700', icon: 'text-amber-700' };
      case TrainingLevelEnum.EXPERT: return { bg: 'bg-indigo-50', text: 'text-indigo-700', icon: 'text-indigo-700' };
      default: return { bg: 'bg-gray-50', text: 'text-gray-700', icon: 'text-gray-700' };
    }
  };

  const levelSummaryColors = getLevelSummaryCardColors(customer.level);
  const canPerformActions = currentUser.role === UserRoleEnum.ADMIN || currentUser.role === UserRoleEnum.MITARBEITER;
  const isCustomerViewing = currentUser.role === UserRoleEnum.KUNDE;

  return (
    <div className="p-6 md:p-8 lg:p-10 min-h-screen">
      <div className="flex items-center justify-between mb-6 flex-wrap gap-4">
        <div className="flex items-center">
          {!isCustomerViewing && (
            <button onClick={() => navigate('/customers')} className="text-gray-500 hover:text-gray-700 mr-4">
              <ArrowLeftIcon className="h-6 w-6" />
            </button>
          )}
          <h1 className="text-2xl font-bold text-gray-900 flex items-center">
            {customer.firstName} {customer.lastName}
            <span className="text-gray-500 font-normal text-base ml-2">
              {isCustomerViewing ? "Meine Übersicht" : "Kundendetails & Übersicht"}
            </span>
          </h1>
        </div>

        {isEditMode ? (
          <div className="flex space-x-3">
            <Button variant="outline" onClick={handleCancelEdit}>Abbrechen</Button>
            <Button variant="success" icon={SaveIcon} onClick={handleSaveChanges}>Speichern</Button>
          </div>
        ) : (
          <div className="flex space-x-3">
            {canPerformActions && (
              <>
                <Button variant="outline" onClick={() => setIsEditModalOpen(true)}>Stammdaten</Button>
                <Button variant="success" onClick={() => setShowTransactionTypeModal(true)}>Transaktionen</Button>
              </>
            )}
            {isCustomerViewing && (
              <Button variant="primary" icon={EditIcon} onClick={handleToggleEditMode}>Meine Daten bearbeiten</Button>
            )}
          </div>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-6">
          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Persönliche Daten</h2>
            <div className="flex items-start">
              <Avatar initials={customer.avatarInitials} color={customer.avatarColor} size="lg" className="mr-6 flex-shrink-0" />
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-12 gap-y-6 flex-grow">
                <DataRow Icon={UserIcon} label="Vorname" value={customer.firstName} />
                <DataRow Icon={UserIcon} label="Nachname" value={customer.lastName} />
                <DataRow Icon={MailIcon} label="E-Mail" value={customer.email} />
                {isEditMode ? (
                  <Input id="phone" label="Telefon" value={editableData.phone} onChange={handleInputChange} />
                ) : (
                  <DataRow Icon={PhoneIcon} label="Telefon" value={customer.phone} />
                )}
                {isEditMode ? (
                  <Input id="dogName" label="Hund" value={editableData.dogName} onChange={handleInputChange} />
                ) : (
                  <DataRow Icon={HeartIcon} label="Hund" value={customer.dogName} />
                )}
                {isEditMode ? (
                  <Input id="chipNumber" label="Chipnummer" value={editableData.chipNumber} onChange={handleInputChange} />
                ) : (
                  <DataRow Icon={CreditCardIcon} label="Chipnummer" value={customer.chipNumber} />
                )}
              </div>
            </div>
          </Card>

          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Übersicht</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="bg-green-50 p-4 rounded-lg flex flex-col justify-center items-center text-center">
                <p className="text-sm text-gray-600 mb-1">Aktuelles Guthaben</p>
                <p className="text-2xl font-bold text-green-700">{customer.balance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}</p>
              </div>
              <button
                onClick={() => setIsTransactionHistoryModalOpen(true)}
                className="bg-blue-50 p-4 rounded-lg flex flex-col justify-center items-center text-center w-full hover:bg-blue-100 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 transition-colors"
              >
                <p className="text-sm text-gray-600 mb-1">Transaktionen gesamt</p>
                <p className="text-2xl font-bold text-blue-700">{customer.totalTransactions}</p>
              </button>
              <div className={`${levelSummaryColors.bg} p-4 rounded-lg flex flex-col justify-center items-center text-center`}>
                <p className="text-sm text-gray-600 mb-1">Level</p>
                <div className="flex items-center mt-2">
                  <AwardIcon className={`h-10 w-10 mr-2 ${levelSummaryColors.icon}`} />
                  <p className={`text-2xl font-bold ${levelSummaryColors.text}`}>{customer.level}</p>
                </div>
              </div>
            </div>
          </Card>

          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Ausbildungsfortschritt</h2>
            <div className="space-y-6">
              {customer.trainingProgress.map((section) => {
                let headerBgClass = 'bg-gray-50';
                let levelCircleBgClass = 'bg-gray-400';

                switch (section.name) {
                  case TrainingLevelEnum.EINSTEIGER: headerBgClass = 'bg-fuchsia-50'; break;
                  case TrainingLevelEnum.GRUNDLAGEN: headerBgClass = 'bg-lime-50'; break;
                  case TrainingLevelEnum.FORTGESCHRITTENE: headerBgClass = 'bg-sky-50'; break;
                  case TrainingLevelEnum.MASTERCLASS: headerBgClass = 'bg-amber-50'; break;
                  case TrainingLevelEnum.EXPERT: headerBgClass = 'bg-indigo-50'; break;
                }
                switch (section.name) {
                  case TrainingLevelEnum.EINSTEIGER: levelCircleBgClass = 'bg-fuchsia-500'; break;
                  case TrainingLevelEnum.GRUNDLAGEN: levelCircleBgClass = 'bg-lime-500'; break;
                  case TrainingLevelEnum.FORTGESCHRITTENE: levelCircleBgClass = 'bg-sky-500'; break;
                  case TrainingLevelEnum.MASTERCLASS: levelCircleBgClass = 'bg-amber-500'; break;
                  case TrainingLevelEnum.EXPERT: levelCircleBgClass = 'bg-indigo-500'; break;
                }

                const isExpanded = expandedSections[section.id];
                return (
                  <div key={section.id} className="rounded-lg overflow-hidden border border-gray-200 shadow-sm">
                    <button
                      className={`p-4 flex items-center justify-between w-full text-left ${headerBgClass}`}
                      onClick={() => toggleSection(section.id)}
                      aria-expanded={isExpanded}
                      aria-controls={`section-content-${section.id}`}
                    >
                      <h3 className="text-lg font-medium text-gray-900 flex items-center">
                        <span className={`flex items-center justify-center h-8 w-8 rounded-full text-white font-bold text-base mr-3 ${levelCircleBgClass}`}>{section.id}</span>
                        {section.name}
                      </h3>
                      <div className="flex items-center">
                        <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${getStatusClasses(section.status)} mr-2`}>{section.status}</span>
                        <ChevronDownIcon className={`h-5 w-5 text-gray-500 transition-transform duration-200 ${isExpanded ? 'rotate-180' : ''}`} />
                      </div>
                    </button>
                    <div id={`section-content-${section.id}`} className={`${isExpanded ? 'block' : 'hidden'} p-4 bg-white border-t border-gray-200`}>
                      {section.name === TrainingLevelEnum.EXPERT ? (
                        (() => {
                          const currentHours = section.completedHours;
                          const fullMilestones = Math.floor(currentHours / 100);
                          const remainingHours = currentHours % 100;
                          return (
                            <>
                              <p className="text-sm text-gray-600 mb-3">Fortschritt: {currentHours} Trails absolviert im Expert-Status</p>
                              <div className="flex flex-wrap gap-2">
                                {Array.from({ length: fullMilestones }).map((_, i) => (<HundredHourMilestoneBadge key={`milestone-${i}`} milestoneNumber={i + 1} />))}
                                {Array.from({ length: remainingHours }).map((_, i) => (<TrainingPawIcon key={`paw-${i}`} filled={true} />))}
                              </div>
                            </>
                          );
                        })()
                      ) : (
                        <>
                          <p className="text-sm text-gray-600 mb-3">Fortschritt: {section.completedHours} / {section.requiredHours} Trails</p>
                          <div className="flex flex-wrap gap-2">
                            {Array.from({ length: section.completedHours }).map((_, i) => (<TrainingPawIcon key={i} filled={true} />))}
                            {Array.from({ length: section.requiredHours - section.completedHours }).map((_, i) => (<TrainingPawIcon key={`empty-${i}`} filled={false} />))}
                          </div>
                        </>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </Card>
        </div>
        <div className="lg:col-span-1 space-y-6">
          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Konto-Übersicht</h2>
            <div className="space-y-2 text-gray-700">
              <div className="flex justify-between"><span>Erstellt am</span><span className="font-bold">{customer.createdAt}</span></div>
              <div className="flex justify-between"><span>Kunden-ID</span><span className="font-bold">{customer.id}</span></div>
            </div>
          </Card>

          <Card className="text-center">
            <h2 className="text-xl font-semibold text-gray-900 mb-4">QR-Code</h2>
            <QRCodeDisplay dataUrl={customer.qrCodeData} className="mb-3" />
            <p className="text-sm text-gray-600">Scannen, um diese Kundenkarte schnell aufzurufen.</p>
          </Card>
        </div>
      </div>
      <TransactionConfirmationModal
        isOpen={showConfirmationModal}
        onClose={() => setShowConfirmationModal(false)}
        onConfirm={handleConfirmTransaction}
        data={transactionData}
      />
      <TransactionTypeSelectionModal
        isOpen={showTransactionTypeModal}
        onClose={() => setShowTransactionTypeModal(false)}
        onSelectType={handleSelectTransactionType}
      />
      <CustomerFormModal
        isOpen={isEditModalOpen}
        onClose={() => setIsEditModalOpen(false)}
        onSubmit={handleUpdateStammdaten}
        customerToEdit={customer}
      />
      <TransactionHistoryModal
        isOpen={isTransactionHistoryModalOpen}
        onClose={() => setIsTransactionHistoryModalOpen(false)}
        transactions={customerTransactions}
        customerName={`${customer.firstName} ${customer.lastName}`}
      />
    </div>
  );
};

export default CustomerDetails;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import Card from '../components/Card';
import Avatar from '../components/Avatar';
import Button from '../components/Button';
import Input from '../components/Input';
import QRCodeDisplay from '../components/QRCodeDisplay';
import TransactionConfirmationModal from '../components/TransactionConfirmationModal';
import TransactionTypeSelectionModal from '../components/TransactionTypeSelectionModal';
import CustomerFormModal from '../components/CustomerFormModal';
import TransactionHistoryModal from '../components/TransactionHistoryModal'; // Import the new modal
import {
  ArrowLeftIcon,
  HeartIcon,
  CreditCardIcon,
  MailIcon,
  PhoneIcon,
  AwardIcon,
  UploadIcon,
  UserIcon,
  ChevronDownIcon,
  EditIcon,
  SaveIcon,
  ArrowUpCircleIcon,
  ArrowDownCircleIcon,
} from '../components/Icons';
import { CURRENT_EMPLOYEE, REFERENCE_DATE } from '../constants';
import { Customer, TrainingLevelEnum, TransactionConfirmationData, Transaction, User, UserRoleEnum, NewCustomerData } from '../types';

interface TrainingHourCircleProps {
  filled: boolean;
  className?: string;
}

const TrainingPawIcon: React.FC<TrainingHourCircleProps> = ({ filled, className = '' }) => (
  <div
    className={`flex items-center justify-center h-16 w-16 rounded-full border
      ${filled ? 'bg-gray-100 border-gray-300' : 'bg-gray-50 border-gray-200'}
      ${className}`}
  >
    <img
      src="https://hs-bw.com/wp-content/uploads/2025/12/Suchund-Icon.png"
      alt="Paw Icon"
      className={`h-10 w-10 object-contain ${!filled ? 'grayscale opacity-50' : ''}`}
    />
  </div>
);

interface HundredHourMilestoneBadgeProps {
  milestoneNumber: number;
}

const HundredHourMilestoneBadge: React.FC<HundredHourMilestoneBadgeProps> = ({ milestoneNumber }) => {
  const baseClasses = "flex flex-col items-center justify-center h-32 w-32 p-2 rounded-lg text-center shadow-md";
  let specificClasses = "";
  let textColor = "text-amber-800";

  switch (milestoneNumber) {
    case 1:
      specificClasses = "bg-amber-100 border border-amber-300";
      break;
    case 2:
      specificClasses = "bg-orange-100 border border-orange-300 shadow-lg";
      textColor = "text-orange-800";
      break;
    case 3:
      specificClasses = "bg-red-100 border border-red-300 shadow-xl";
      textColor = "text-red-800";
      break;
    case 4:
      specificClasses = "bg-purple-100 border border-purple-300 shadow-2xl";
      textColor = "text-purple-800";
      break;
    case 5:
      specificClasses = "bg-blue-100 border border-blue-300 shadow-2xl";
      textColor = "text-blue-800";
      break;
    default:
      specificClasses = "bg-gray-100 border border-gray-300";
      textColor = "text-gray-800";
      break;
  }

  return (
    <div className={`${baseClasses} ${specificClasses}`}>
      <img
        src="https://hs-bw.com/wp-content/uploads/2025/12/Suchund-Icon.png"
        alt={`${milestoneNumber * 100} Trails gemeistert`}
        className="h-20 w-20 object-contain filter drop-shadow-sm"
      />
      <p className={`text-sm font-bold ${textColor} mt-1`}>{milestoneNumber * 100} Trails gemeistert!</p>
    </div>
  );
};

interface CustomerDetailsProps {
  customers: Customer[];
  transactions: Transaction[];
  onUpdateCustomer: (updatedCustomer: Customer) => void;
  onAddTransaction: (newTransaction: Transaction) => void;
  currentUser: User;
}

const CustomerDetails: React.FC<CustomerDetailsProps> = ({
  customers,
  transactions,
  onUpdateCustomer,
  onAddTransaction,
  currentUser,
}) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [showConfirmationModal, setShowConfirmationModal] = useState(false);
  const [showTransactionTypeModal, setShowTransactionTypeModal] = useState(false);
  const [isTransactionHistoryModalOpen, setIsTransactionHistoryModalOpen] = useState(false);
  const [transactionData, setTransactionData] = useState<TransactionConfirmationData | null>(null);
  const [customer, setCustomer] = useState<Customer | null>(null);
  const [isLoadingCustomer, setIsLoadingCustomer] = useState(true);
  const [isEditMode, setIsEditMode] = useState(false);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editableData, setEditableData] = useState({
    phone: '',
    dogName: '',
    chipNumber: '',
  });

  useEffect(() => {
    setIsLoadingCustomer(true);
    if (id) {
      const foundCustomer = customers.find((c) => c.id === id);
      setCustomer(foundCustomer || null);

      if (foundCustomer) {
        setEditableData({
          phone: foundCustomer.phone,
          dogName: foundCustomer.dogName,
          chipNumber: foundCustomer.chipNumber,
        });
      }
    } else {
      setCustomer(null);
    }
    setIsLoadingCustomer(false);
  }, [id, customers]);

  // Authorization Effect: Redirect if a customer tries to access another customer's page
  useEffect(() => {
    if (currentUser.role === UserRoleEnum.KUNDE && currentUser.associatedCustomerId && id !== currentUser.associatedCustomerId) {
        navigate(`/customers/${currentUser.associatedCustomerId}`, { replace: true });
    }
  }, [currentUser, id, navigate]);

  const [expandedSections, setExpandedSections] = useState<Record<number, boolean>>({});

  useEffect(() => {
    if (customer) {
      setExpandedSections(prev => {
        const newExpanded = { ...prev };
        customer.trainingProgress.forEach(section => {
          if (newExpanded[section.id] === undefined) {
            newExpanded[section.id] = false;
          }
        });
        return newExpanded;
      });
    }
  }, [customer]);

  // Filter and sort transactions for the current customer
  const customerTransactions = transactions
    .filter(t => t.customerId === id)
    .sort((a, b) => {
      const dateA = new Date(a.date.split('.').reverse().join('-'));
      const dateB = new Date(b.date.split('.').reverse().join('-'));
      return dateB.getTime() - dateA.getTime();
    });

  if (!id) {
    return (
      <div className="p-8 text-center text-red-600">
        Keine Kunden-ID in der URL gefunden.
        <Button variant="primary" onClick={() => navigate('/customers')} className="mt-4">
          Zurück zur Kundenliste
        </Button>
      </div>
    );
  }

  if (isLoadingCustomer) {
    return <div className="p-8 text-center text-gray-600">Lade Kundendaten...</div>;
  }

  if (!customer) {
    return (
      <div className="p-8 text-center text-gray-600">
        Kunde mit ID "{id}" nicht gefunden.
        <Button variant="primary" onClick={() => navigate('/customers')} className="mt-4">
          Zurück zur Kundenliste
        </Button>
      </div>
    );
  }

  const handleOpenConfirmationModal = (amount: number, type: 'Aufladung' | 'Abbuchung', description?: string) => {
    const oldBalance = customer.balance;
    const newBalance = type === 'Aufladung' ? oldBalance + amount : oldBalance - amount;
    setTransactionData({
      customerId: customer.id,
      customerName: `${customer.firstName} ${customer.lastName}`,
      employee: CURRENT_EMPLOYEE,
      transactionType: type,
      amount: amount,
      oldBalance: oldBalance,
      newBalance: newBalance,
      description: description,
    });
    setShowConfirmationModal(true);
  };

  const handleConfirmTransaction = () => {
    if (!transactionData || !customer) return;

    let finalUpdatedCustomer: Customer = { ...customer };
    finalUpdatedCustomer.balance = transactionData.newBalance;
    finalUpdatedCustomer.totalTransactions = customer.totalTransactions + 1;

    const isRecharge = transactionData.transactionType === 'Aufladung';
    if (!isRecharge && transactionData.description === 'Trails' && transactionData.amount === 18) {
      const currentTrainingProgress = [...customer.trainingProgress];
      let customerOverallLevel = finalUpdatedCustomer.level;
      const currentLevelIndex = currentTrainingProgress.findIndex(s => s.status === 'Aktuell');

      if (currentLevelIndex !== -1) {
        const currentSection = { ...currentTrainingProgress[currentLevelIndex] };
        if (currentSection.name === TrainingLevelEnum.EXPERT) {
          if (currentSection.completedHours < 500) {
            currentSection.completedHours += 1;
            currentTrainingProgress[currentLevelIndex] = currentSection;
          }
        } else if (currentSection.completedHours < currentSection.requiredHours) {
          currentSection.completedHours += 1;
          if (currentSection.completedHours === currentSection.requiredHours) {
            currentSection.status = 'Abgeschlossen';
            const nextLevelIndex = currentLevelIndex + 1;
            if (nextLevelIndex < currentTrainingProgress.length) {
              const nextSection = { ...currentTrainingProgress[nextLevelIndex] };
              nextSection.status = 'Aktuell';
              customerOverallLevel = nextSection.name;
              currentTrainingProgress[nextLevelIndex] = nextSection;
            }
          }
          currentTrainingProgress[currentLevelIndex] = currentSection;
        }
        finalUpdatedCustomer.trainingProgress = currentTrainingProgress;
        finalUpdatedCustomer.level = customerOverallLevel;
      }
    }

    onUpdateCustomer(finalUpdatedCustomer);

    const newTransaction: Transaction = {
      id: `trx-${transactions.length + 1}-${Date.now()}`,
      customerId: customer.id,
      type: transactionData.transactionType === 'Aufladung' ? 'recharge' : 'debit',
      description: transactionData.description || (transactionData.transactionType === 'Aufladung' ? 'Aufladung' : 'Trails'),
      amount: transactionData.amount,
      date: REFERENCE_DATE.toLocaleDateString('de-DE'),
      employee: CURRENT_EMPLOYEE,
    };
    onAddTransaction(newTransaction);
    setShowConfirmationModal(false);
    setTransactionData(null);
  };

  const handleSelectTransactionType = (type: 'Aufladung' | 'Abbuchung') => {
    setShowTransactionTypeModal(false);
    let defaultAmount = type === 'Aufladung' ? 215 : 18;
    let description = type === 'Aufladung' ? 'Guthabenaufladung' : 'Trails';
    handleOpenConfirmationModal(defaultAmount, type, description);
  };

  const handleToggleEditMode = () => {
    if (!isEditMode) {
      setEditableData({
        phone: customer.phone,
        dogName: customer.dogName,
        chipNumber: customer.chipNumber,
      });
    }
    setIsEditMode(!isEditMode);
  };

  const handleCancelEdit = () => {
    setIsEditMode(false);
  };

  const handleSaveChanges = () => {
    const updatedCustomer = {
      ...customer,
      phone: editableData.phone,
      dogName: editableData.dogName,
      chipNumber: editableData.chipNumber,
    };
    onUpdateCustomer(updatedCustomer);
    setIsEditMode(false);
  };

  const handleUpdateStammdaten = (data: NewCustomerData) => {
    if (!customer) return;
    const updatedCustomer = { ...customer, ...data };
    onUpdateCustomer(updatedCustomer);
    setIsEditModalOpen(false);
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { id, value } = e.target;
    setEditableData(prev => ({ ...prev, [id]: value }));
  };

  const getStatusClasses = (status: string) => {
    switch (status) {
      case 'Aktuell': return 'bg-green-100 text-green-800';
      case 'Gesperrt': return 'bg-red-100 text-red-800';
      case 'Abgeschlossen': return 'bg-blue-100 text-blue-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const DataRow: React.FC<{ Icon: React.ElementType; label: string; value: string | number }> = ({ Icon, label, value }) => (
    <div>
      <div className="flex items-center text-gray-500 mb-1">
        <Icon className="h-4 w-4 mr-2" />
        <span className="text-sm font-medium">{label}</span>
      </div>
      <p className="font-semibold text-gray-900 ml-6">{value}</p>
    </div>
  );

  const toggleSection = (sectionId: number) => {
    setExpandedSections(prev => ({ ...prev, [sectionId]: !prev[sectionId] }));
  };

  const getLevelSummaryCardColors = (level: TrainingLevelEnum) => {
    switch (level) {
      case TrainingLevelEnum.EINSTEIGER: return { bg: 'bg-fuchsia-50', text: 'text-fuchsia-700', icon: 'text-fuchsia-700' };
      case TrainingLevelEnum.GRUNDLAGEN: return { bg: 'bg-lime-50', text: 'text-lime-700', icon: 'text-lime-700' };
      case TrainingLevelEnum.FORTGESCHRITTENE: return { bg: 'bg-sky-50', text: 'text-sky-700', icon: 'text-sky-700' };
      case TrainingLevelEnum.MASTERCLASS: return { bg: 'bg-amber-50', text: 'text-amber-700', icon: 'text-amber-700' };
      case TrainingLevelEnum.EXPERT: return { bg: 'bg-indigo-50', text: 'text-indigo-700', icon: 'text-indigo-700' };
      default: return { bg: 'bg-gray-50', text: 'text-gray-700', icon: 'text-gray-700' };
    }
  };

  const levelSummaryColors = getLevelSummaryCardColors(customer.level);
  const canPerformActions = currentUser.role === UserRoleEnum.ADMIN || currentUser.role === UserRoleEnum.MITARBEITER;
  const isCustomerViewing = currentUser.role === UserRoleEnum.KUNDE;

  return (
    <div className="p-6 md:p-8 lg:p-10 min-h-screen">
      <div className="flex items-center justify-between mb-6 flex-wrap gap-4">
        <div className="flex items-center">
          {!isCustomerViewing && (
            <button onClick={() => navigate('/customers')} className="text-gray-500 hover:text-gray-700 mr-4">
              <ArrowLeftIcon className="h-6 w-6" />
            </button>
          )}
          <h1 className="text-2xl font-bold text-gray-900 flex items-center">
            {customer.firstName} {customer.lastName}
            <span className="text-gray-500 font-normal text-base ml-2">
              {isCustomerViewing ? "Meine Übersicht" : "Kundendetails & Übersicht"}
            </span>
          </h1>
        </div>

        {isEditMode ? (
          <div className="flex space-x-3">
            <Button variant="outline" onClick={handleCancelEdit}>Abbrechen</Button>
            <Button variant="success" icon={SaveIcon} onClick={handleSaveChanges}>Speichern</Button>
          </div>
        ) : (
          <div className="flex space-x-3">
            {canPerformActions && (
              <>
                <Button variant="outline" onClick={() => setIsEditModalOpen(true)}>Stammdaten</Button>
                <Button variant="success" onClick={() => setShowTransactionTypeModal(true)}>Transaktionen</Button>
              </>
            )}
            {isCustomerViewing && (
              <Button variant="primary" icon={EditIcon} onClick={handleToggleEditMode}>Meine Daten bearbeiten</Button>
            )}
          </div>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-6">
          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Persönliche Daten</h2>
            <div className="flex items-start">
              <Avatar initials={customer.avatarInitials} color={customer.avatarColor} size="lg" className="mr-6 flex-shrink-0" />
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-12 gap-y-6 flex-grow">
                <DataRow Icon={UserIcon} label="Vorname" value={customer.firstName} />
                <DataRow Icon={UserIcon} label="Nachname" value={customer.lastName} />
                <DataRow Icon={MailIcon} label="E-Mail" value={customer.email} />
                {isEditMode ? (
                  <Input id="phone" label="Telefon" value={editableData.phone} onChange={handleInputChange} />
                ) : (
                  <DataRow Icon={PhoneIcon} label="Telefon" value={customer.phone} />
                )}
                {isEditMode ? (
                  <Input id="dogName" label="Hund" value={editableData.dogName} onChange={handleInputChange} />
                ) : (
                  <DataRow Icon={HeartIcon} label="Hund" value={customer.dogName} />
                )}
                {isEditMode ? (
                  <Input id="chipNumber" label="Chipnummer" value={editableData.chipNumber} onChange={handleInputChange} />
                ) : (
                  <DataRow Icon={CreditCardIcon} label="Chipnummer" value={customer.chipNumber} />
                )}
              </div>
            </div>
          </Card>

          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Übersicht</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="bg-green-50 p-4 rounded-lg flex flex-col justify-center items-center text-center">
                <p className="text-sm text-gray-600 mb-1">Aktuelles Guthaben</p>
                <p className="text-2xl font-bold text-green-700">{customer.balance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}</p>
              </div>
              <button
                onClick={() => setIsTransactionHistoryModalOpen(true)}
                className="bg-blue-50 p-4 rounded-lg flex flex-col justify-center items-center text-center w-full hover:bg-blue-100 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 transition-colors"
              >
                <p className="text-sm text-gray-600 mb-1">Transaktionen gesamt</p>
                <p className="text-2xl font-bold text-blue-700">{customer.totalTransactions}</p>
              </button>
              <div className={`${levelSummaryColors.bg} p-4 rounded-lg flex flex-col justify-center items-center text-center`}>
                <p className="text-sm text-gray-600 mb-1">Level</p>
                <div className="flex items-center mt-2">
                  <AwardIcon className={`h-10 w-10 mr-2 ${levelSummaryColors.icon}`} />
                  <p className={`text-2xl font-bold ${levelSummaryColors.text}`}>{customer.level}</p>
                </div>
              </div>
            </div>
          </Card>

          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Ausbildungsfortschritt</h2>
            <div className="space-y-6">
              {customer.trainingProgress.map((section) => {
                let headerBgClass = 'bg-gray-50';
                let levelCircleBgClass = 'bg-gray-400';

                switch (section.name) {
                  case TrainingLevelEnum.EINSTEIGER: headerBgClass = 'bg-fuchsia-50'; break;
                  case TrainingLevelEnum.GRUNDLAGEN: headerBgClass = 'bg-lime-50'; break;
                  case TrainingLevelEnum.FORTGESCHRITTENE: headerBgClass = 'bg-sky-50'; break;
                  case TrainingLevelEnum.MASTERCLASS: headerBgClass = 'bg-amber-50'; break;
                  case TrainingLevelEnum.EXPERT: headerBgClass = 'bg-indigo-50'; break;
                }
                switch (section.name) {
                  case TrainingLevelEnum.EINSTEIGER: levelCircleBgClass = 'bg-fuchsia-500'; break;
                  case TrainingLevelEnum.GRUNDLAGEN: levelCircleBgClass = 'bg-lime-500'; break;
                  case TrainingLevelEnum.FORTGESCHRITTENE: levelCircleBgClass = 'bg-sky-500'; break;
                  case TrainingLevelEnum.MASTERCLASS: levelCircleBgClass = 'bg-amber-500'; break;
                  case TrainingLevelEnum.EXPERT: levelCircleBgClass = 'bg-indigo-500'; break;
                }

                const isExpanded = expandedSections[section.id];
                return (
                  <div key={section.id} className="rounded-lg overflow-hidden border border-gray-200 shadow-sm">
                    <button
                      className={`p-4 flex items-center justify-between w-full text-left ${headerBgClass}`}
                      onClick={() => toggleSection(section.id)}
                      aria-expanded={isExpanded}
                      aria-controls={`section-content-${section.id}`}
                    >
                      <h3 className="text-lg font-medium text-gray-900 flex items-center">
                        <span className={`flex items-center justify-center h-8 w-8 rounded-full text-white font-bold text-base mr-3 ${levelCircleBgClass}`}>{section.id}</span>
                        {section.name}
                      </h3>
                      <div className="flex items-center">
                        <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${getStatusClasses(section.status)} mr-2`}>{section.status}</span>
                        <ChevronDownIcon className={`h-5 w-5 text-gray-500 transition-transform duration-200 ${isExpanded ? 'rotate-180' : ''}`} />
                      </div>
                    </button>
                    <div id={`section-content-${section.id}`} className={`${isExpanded ? 'block' : 'hidden'} p-4 bg-white border-t border-gray-200`}>
                      {section.name === TrainingLevelEnum.EXPERT ? (
                        (() => {
                          const currentHours = section.completedHours;
                          const fullMilestones = Math.floor(currentHours / 100);
                          const remainingHours = currentHours % 100;
                          return (
                            <>
                              <p className="text-sm text-gray-600 mb-3">Fortschritt: {currentHours} Trails absolviert im Expert-Status</p>
                              <div className="flex flex-wrap gap-2">
                                {Array.from({ length: fullMilestones }).map((_, i) => (<HundredHourMilestoneBadge key={`milestone-${i}`} milestoneNumber={i + 1} />))}
                                {Array.from({ length: remainingHours }).map((_, i) => (<TrainingPawIcon key={`paw-${i}`} filled={true} />))}
                              </div>
                            </>
                          );
                        })()
                      ) : (
                        <>
                          <p className="text-sm text-gray-600 mb-3">Fortschritt: {section.completedHours} / {section.requiredHours} Trails</p>
                          <div className="flex flex-wrap gap-2">
                            {Array.from({ length: section.completedHours }).map((_, i) => (<TrainingPawIcon key={i} filled={true} />))}
                            {Array.from({ length: section.requiredHours - section.completedHours }).map((_, i) => (<TrainingPawIcon key={`empty-${i}`} filled={false} />))}
                          </div>
                        </>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </Card>
        </div>
        <div className="lg:col-span-1 space-y-6">
          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Konto</h2>
            <div className="space-y-2 text-gray-700">
              <div className="flex justify-between"><span>Erstellt am</span><span className="font-bold">{customer.createdAt}</span></div>
              <div className="flex justify-between"><span>Kunden-ID</span><span className="font-bold">{customer.id}</span></div>
            </div>
          </Card>

          <Card className="text-center">
            <h2 className="text-xl font-semibold text-gray-900 mb-4">QR-Code</h2>
            <QRCodeDisplay dataUrl={customer.qrCodeData} className="mb-3" />
            <p className="text-sm text-gray-600">Scannen, um diese Kundenkarte schnell aufzurufen.</p>
          </Card>
        </div>
      </div>
      <TransactionConfirmationModal
        isOpen={showConfirmationModal}
        onClose={() => setShowConfirmationModal(false)}
        onConfirm={handleConfirmTransaction}
        data={transactionData}
      />
      <TransactionTypeSelectionModal
        isOpen={showTransactionTypeModal}
        onClose={() => setShowTransactionTypeModal(false)}
        onSelectType={handleSelectTransactionType}
      />
      <CustomerFormModal
        isOpen={isEditModalOpen}
        onClose={() => setIsEditModalOpen(false)}
        onSubmit={handleUpdateStammdaten}
        customerToEdit={customer}
      />
      <TransactionHistoryModal
        isOpen={isTransactionHistoryModalOpen}
        onClose={() => setIsTransactionHistoryModalOpen(false)}
        transactions={customerTransactions}
        customerName={`${customer.firstName} ${customer.lastName}`}
      />
    </div>
  );
};

export default CustomerDetails;

import React, { useState } from 'react';
import Card from '../components/Card';
import Input from '../components/Input';
import Button from '../components/Button';

interface LoginPageProps {
  onLogin: (email: string, password: string) => boolean;
  onRegister: (email: string, password: string) => boolean;
}

const LoginPage: React.FC<LoginPageProps> = ({ onLogin, onRegister }) => {
  const [isRegisterMode, setIsRegisterMode] = useState(false);
  const [email, setEmail] = useState('admin@pfotencard.de');
  const [password, setPassword] = useState('adminpassword');
  const [confirmPassword, setConfirmPassword] = useState('');

  const [emailError, setEmailError] = useState('');
  const [passwordError, setPasswordError] = useState('');
  const [confirmPasswordError, setConfirmPasswordError] = useState('');
  const [apiError, setApiError] = useState('');

  const resetForm = (switchToRegister: boolean) => {
    setIsRegisterMode(switchToRegister);
    setEmail(switchToRegister ? '' : 'admin@pfotencard.de');
    setPassword(switchToRegister ? '' : 'adminpassword');
    setConfirmPassword('');
    setEmailError('');
    setPasswordError('');
    setConfirmPasswordError('');
    setApiError('');
  };

  const validateForm = () => {
    let isValid = true;
    setEmailError('');
    setPasswordError('');
    setConfirmPasswordError('');
    setApiError('');

    if (!email.trim()) {
      setEmailError('E-Mail ist erforderlich.');
      isValid = false;
    } else if (!/\S+@\S+\.\S+/.test(email)) {
      setEmailError('Ungültiges E-Mail-Format.');
      isValid = false;
    }

    if (!password.trim()) {
      setPasswordError('Passwort ist erforderlich.');
      isValid = false;
    } else if (password.length < 6) {
      setPasswordError('Passwort muss mindestens 6 Zeichen lang sein.');
      isValid = false;
    }

    if (isRegisterMode) {
      if (password !== confirmPassword) {
        setConfirmPasswordError('Die Passwörter stimmen nicht überein.');
        isValid = false;
      }
    }

    return isValid;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validateForm()) {
      let success = false;
      if (isRegisterMode) {
        success = onRegister(email, password);
        if (!success) {
          setApiError('Die Registrierung ist fehlgeschlagen. Die E-Mail könnte bereits vergeben sein.');
        }
      } else {
        success = onLogin(email, password);
        if (!success) {
          setApiError('Ungültige E-Mail oder ungültiges Passwort.');
        }
      }
    }
  };

  return (
    <div className="flex items-center justify-center min-h-screen w-full bg-gray-100 p-4">
      <Card className="max-w-md w-full p-8">
        <h1 className="text-3xl font-bold text-gray-900 text-center mb-6">Mantrailing Card</h1>
        <p className="text-gray-600 text-center mb-8">
          {isRegisterMode ? 'Erstellen Sie Ihr neues Kundenkonto' : 'Melden Sie sich an, um fortzufahren'}
        </p>

        <form onSubmit={handleSubmit} className="space-y-6">
          <Input
            id="loginEmail"
            label="E-Mail"
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="ihre.email@example.com"
            error={emailError}
          />
          <Input
            id="loginPassword"
            label="Passwort"
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="********"
            error={passwordError}
          />
          {isRegisterMode && (
            <Input
              id="confirmPassword"
              label="Passwort bestätigen"
              type="password"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              placeholder="********"
              error={confirmPasswordError}
            />
          )}

          {apiError && (
            <div className="text-red-600 text-sm text-center -mt-4">
              {apiError}
            </div>
          )}

          <Button type="submit" variant="primary" className="w-full">
            {isRegisterMode ? 'Registrieren' : 'Anmelden'}
          </Button>
        </form>

        <div className="text-center mt-6">
          <button onClick={() => resetForm(!isRegisterMode)} className="text-sm text-blue-600 hover:underline">
            {isRegisterMode ? 'Bereits ein Konto? Jetzt anmelden' : 'Noch kein Konto? Jetzt registrieren'}
          </button>
        </div>

      </Card>
    </div>
  );
};

export default LoginPage;

payload.text:
Absolut. Der Übergang von Mock-Daten zu einer echten Datenbankanbindung ist der wichtigste Schritt, um Ihre Anwendung robust, skalierbar und praxistauglich zu machen. Es ist ein fundamentaler Wandel von einer reinen Frontend-Demo zu einer vollwertigen Full-Stack-Anwendung.

Als erfahrener Senior Engineer schlage ich Ihnen einen strukturierten, phasenweisen Ansatz vor. Das macht den Prozess überschaubar und minimiert Risiken.

Hier ist Ihre vernünftige Schritt-für-Schritt-Anleitung:

### Übersicht der Architektur

Bevor wir beginnen, hier das Zielbild unserer neuen Architektur:

1.  **Frontend (Ihre React App):** Bleibt die Benutzeroberfläche. Statt Mock-Daten zu lesen, wird sie HTTP-Anfragen an unser neues Backend senden, um Daten abzurufen und zu ändern.
2.  **Backend (API-Server):** Ein neuer Server, der als Vermittler zwischen dem Frontend und der Datenbank dient. Er enthält die Geschäftslogik (z. B. wie ein Trail-Fortschritt berechnet wird) und stellt Endpunkte bereit (z. B. `/api/customers`), die das Frontend aufrufen kann.
3.  **Datenbank:** Das neue persistente Gedächtnis Ihrer Anwendung. Hier werden alle Kunden, Benutzer und Transaktionen sicher gespeichert.

---

### Phase 1: Backend-Entwicklung und API-Design

In dieser Phase bauen wir das Fundament. Das Frontend wird vorerst nicht angefasst.

#### Schritt 1: Technologie-Stack für das Backend wählen

Wir benötigen eine serverseitige Technologie. Da Ihr Frontend bereits auf React (JavaScript/TypeScript) basiert, ist die naheliegendste und effizienteste Wahl:

*   **Laufzeitumgebung:** **Node.js** – Ermöglicht es uns, JavaScript/TypeScript auf dem Server auszuführen.
*   **Framework:** **Express.js** – Ein schlankes, aber leistungsstarkes Framework für den Aufbau der API.
*   **Sprache:** **TypeScript** – Um Konsistenz mit dem Frontend zu wahren und von Typsicherheit zu profitieren.

**Empfehlung:** Ein Node.js + Express.js + TypeScript Backend.

#### Schritt 2: Datenbank auswählen

Ihre Daten (Kunden, Transaktionen) sind stark strukturiert und relational. Daher ist eine SQL-Datenbank die beste Wahl.

*   **Empfehlung:** **PostgreSQL**. Es ist open-source, extrem robust, skalierbar und der Industriestandard für ernsthafte Anwendungen.
*   **Alternative:** **MySQL/MariaDB**. Ebenfalls eine sehr solide Wahl.

Für den Anfang können Sie eine kostenlose PostgreSQL-Datenbank bei Anbietern wie [Supabase](https://supabase.com/), [Neon](https://neon.tech/) oder [Render](https://render.com/) einrichten, was Ihnen die Server-Administration abnimmt.

#### Schritt 3: API-Design (Der Vertrag zwischen Frontend und Backend)

Wir definieren, wie Frontend und Backend miteinander kommunizieren. Eine **RESTful API** ist hier der Standard. Wir definieren die "Endpunkte" (URLs), die unsere App benötigt:

*   **Authentifizierung:**
    *   `POST /api/auth/login` - Zum Anmelden eines Benutzers.
    *   `POST /api/auth/register` - Zum Registrieren eines neuen Kunden.
    *   `POST /api/auth/logout` - Zum Abmelden.

*   **Kunden (Customers):**
    *   `GET /api/customers` - Ruft alle Kunden ab.
    *   `GET /api/customers/:id` - Ruft einen spezifischen Kunden ab.
    *   `POST /api/customers` - Erstellt einen neuen Kunden (für Admins).
    *   `PUT /api/customers/:id` - Aktualisiert die Daten eines Kunden.

*   **Benutzer (Users):**
    *   `GET /api/users` - Ruft alle Mitarbeiter/Admins ab.
    *   `POST /api/users` - Erstellt einen neuen Mitarbeiter.
    *   `PUT /api/users/:id` - Aktualisiert einen Mitarbeiter.
    *   `DELETE /api/users/:id` - Löscht einen Mitarbeiter.

*   **Transaktionen (Transactions):**
    *   `GET /api/customers/:customerId/transactions` - Ruft alle Transaktionen für einen Kunden ab.
    *   `POST /api/customers/:customerId/transactions` - Erstellt eine neue Transaktion für einen Kunden (Aufladung/Abbuchung).

#### Schritt 4: Authentifizierung und Autorisierung implementieren

Dies ist ein kritischer Schritt. Die reine Frontend-Anmeldung wird durch einen sicheren serverseitigen Prozess ersetzt.

1.  **Login-Prozess:** Der `POST /api/auth/login`-Endpunkt prüft E-Mail und Passwort (sicher als Hash in der DB gespeichert) ab.
2.  **Token-Erstellung:** Bei Erfolg generiert der Server ein **JSON Web Token (JWT)**. Dieses Token ist wie ein digitaler Ausweis für den Benutzer.
3.  **Token-Speicherung:** Das Frontend speichert dieses JWT sicher (z. B. im `localStorage`).
4.  **Autorisierte Anfragen:** Für jede weitere Anfrage (z. B. `GET /api/customers`) sendet das Frontend das JWT im `Authorization`-Header mit.
5.  **Serverseitige Prüfung:** Das Backend validiert bei *jeder* Anfrage das JWT und prüft die Berechtigungen (Rolle) des Benutzers, bevor es Daten zurückgibt. **Die Logik, wer was darf, liegt ausschließlich im Backend!**

---

### Phase 2: Frontend-Anpassung

Jetzt, wo das Backend-Fundament geplant ist, passen wir das Frontend an, um es zu nutzen.

#### Schritt 5: Eine API-Service-Schicht erstellen

Wir werden nicht `fetch()`-Aufrufe in der gesamten App verstreuen. Stattdessen schaffen wir eine zentrale Stelle für die API-Kommunikation.

*   Erstellen Sie einen neuen Ordner, z. B. `src/services/`.
*   Darin erstellen Sie Dateien wie `apiClient.ts`, `customerService.ts`, `authService.ts`.
*   **Beispiel (`customerService.ts`):**
    ```typescript
    import apiClient from './apiClient';
    import { Customer } from '../types';

    export const getAllCustomers = async (): Promise<Customer[]> => {
      const response = await apiClient.get('/customers');
      return response.data;
    };

    export const getCustomerById = async (id: string): Promise<Customer> => {
      // ...
    };
    ```

#### Schritt 6: Mock-Daten durch API-Aufrufe ersetzen

Dies ist die Kernarbeit im Frontend.

1.  **Entfernen der `INITIAL_MOCK_...`-Daten** aus `App.tsx`. Die `useState`-Haken für `customers`, `transactions` etc. werden ebenfalls entfernt. Die Datenhoheit liegt nun im Backend.
2.  **Datenabruf in Komponenten:** Jede Seite, die Daten benötigt, ruft diese nun selbst ab.
    *   **Beispiel in `CustomerManagement.tsx`:**
        ```tsx
        import React, { useState, useEffect } from 'react';
        import { getAllCustomers } from '../services/customerService';

        const CustomerManagement = () => {
          const [customers, setCustomers] = useState([]);
          const [isLoading, setIsLoading] = useState(true);
          const [error, setError] = useState<string | null>(null);

          useEffect(() => {
            getAllCustomers()
              .then(data => setCustomers(data))
              .catch(err => setError('Fehler beim Laden der Kundendaten.'))
              .finally(() => setIsLoading(false));
          }, []);

          if (isLoading) return <div>Lade Kunden...</div>;
          if (error) return <div className="text-red-500">{error}</div>;

          // ... Rest der Komponente mit den 'customers' Daten
        };
        ```

#### Schritt 7: Formulare und Datenänderungen (Mutationen) anpassen

Wenn ein Formular abgeschickt wird (z. B. "Neuer Mitarbeiter"), wird statt des lokalen `onAddUser`-Props eine API-Funktion aufgerufen.

*   **Beispiel in `UserManagement.tsx`:**
    ```tsx
    import { createUser } from '../services/userService';

    const handleSubmitUserForm = async (userData) => {
      try {
        const newUser = await createUser(userData);
        // Nach Erfolg: UI aktualisieren (z.B. die Liste neu laden)
        // ...
      } catch (error) {
        // Fehler anzeigen
      }
    };
    ```

#### Schritt 8: Zustandsverwaltung für Serverdaten optimieren (Empfehlung)

Ständig Lade- und Fehlerzustände manuell zu verwalten, ist mühsam. Eine Bibliothek wie **TanStack Query (früher React Query)** ist hier der Goldstandard. Sie kümmert sich um Caching, Hintergrund-Aktualisierungen und das Management von Server-Zuständen, was Ihren Code drastisch vereinfacht und die UX verbessert.

---

### Phase 3: Deployment

Sobald alles lokal funktioniert, muss die Anwendung live gehen.

#### Schritt 9: Backend und Datenbank deployen

*   **Backend:** Plattformen wie **Render**, **Heroku** oder **Vercel (für Serverless Functions)** sind hervorragend geeignet, um Ihren Node.js-Server zu hosten.
*   **Datenbank:** Nutzen Sie einen gemanagten Service (siehe Schritt 2), um sich nicht um die Wartung kümmern zu müssen.

#### Schritt 10: Umgebungsvariablen (Environment Variables) einrichten

Wichtige und geheime Informationen wie Datenbank-Passwörter oder der JWT-Secret-Key gehören **niemals** in den Code. Sie werden über Umgebungsvariablen konfiguriert, die von der Hosting-Plattform bereitgestellt werden.

### Ihr nächster Schritt

Das war eine Menge an Informationen. Keine Sorge, wir gehen das Schritt für Schritt an.

**Mein Vorschlag für den unmittelbaren Start:**

Sagen Sie mir Bescheid, und ich beginne mit **Schritt 1 und 3**: Ich erstelle die grundlegende Projektstruktur für das Node.js/Express-Backend und definiere die Ordnerstruktur sowie die erste API-Route (z.B. `GET /api/customers`), die vorerst noch statische JSON-Daten zurückgibt.

So haben Sie ein funktionierendes Backend-Grundgerüst, auf dem wir aufbauen können. Bereit?

