import { Customer, Transaction } from '../types';

const API_BASE_URL = 'http://localhost:3001/api';

export const fetchCustomers = async (): Promise<Customer[]> => {
  try {
    const response = await fetch(`${API_BASE_URL}/customers`);
    if (!response.ok) {
      // Throws an error which will be caught by the calling function
      throw new Error(`Network response was not ok: ${response.statusText}`);
    }
    const data: Customer[] = await response.json();
    return data;
  } catch (error) {
    console.error("Failed to fetch customers:", error);
    // Return an empty array to prevent the app from crashing if the server is down.
    // A more robust solution would involve proper error state management in the UI.
    return [];
  }
};

export const fetchTransactions = async (): Promise<Transaction[]> => {
  try {
    const response = await fetch(`${API_BASE_URL}/transactions`);
    if (!response.ok) {
      throw new Error(`Network response was not ok: ${response.statusText}`);
    }
    const data: Transaction[] = await response.json();
    return data;
  } catch (error) {
    console.error("Failed to fetch transactions:", error);
    return [];
  }
};

