import React from 'react';

export interface Customer {
  id: string;
  avatarInitials: string;
  avatarColor: string;
  firstName: string;
  lastName: string;
  email: string;
  phone: string;
  dogName: string;
  chipNumber: string;
  balance: number;
  totalTransactions: number;
  level: TrainingLevelEnum;
  createdAt: string; // Reverted from Date back to string
  createdBy: string;
  qrCodeData: string;
  documents: Document[];
  trainingProgress: TrainingSection[];
  // Transactions are fetched separately, so not included here to avoid deep nesting
}

// New type for the customer editing form
export interface NewCustomerData {
  firstName: string;
  lastName: string;
  email: string; // Will be read-only in the form
  phone: string;
  dogName: string;
  chipNumber: string;
}

export interface Transaction {
  id: string;
  customerId: string;
  type: 'recharge' | 'debit';
  description: string;
  amount: number;
  date: string; // This remains a string for frontend display, but will be a Date from the DB
  employee: string;
}

export enum TrainingLevelEnum {
  EINSTEIGER = 'Einsteiger',
  GRUNDLAGEN = 'Grundlagen',
  FORTGESCHRITTENE = 'Fortgeschrittene',
  MASTERCLASS = 'Masterclass',
  EXPERT = 'Expert',
}

export interface TrainingSection {
  id: number;
  name: TrainingLevelEnum;
  requiredHours: number;
  completedHours: number;
  status: 'Aktuell' | 'Gesperrt' | 'Abgeschlossen';
  customerId?: string; // Optional as it might not be needed in all frontend contexts
}

export interface Document {
  id: string;
  name: string;
  url: string;
  customerId?: string; // Optional
}

export interface StatCardProps {
  title: string;
  value: string | number;
  icon: React.ElementType; // SVG component
  color: string; // Tailwind color class
  description?: string;
