// Function to generate customer users based on existing customers
const generateCustomerUsers = (customers: Customer[], existingUsers: User[]): User[] => {
  const customerUsers: User[] = [...existingUsers];
  const avatarColors = ['bg-red-500', 'bg-orange-500', 'bg-purple-500', 'bg-indigo-500', 'bg-blue-500', 'bg-green-500', 'bg-teal-500', 'bg-fuchsia-500', 'bg-lime-500'];

  customers.forEach(customer => {
    // Check if a customer user already exists for this customerId
    const existingCustomerUser = existingUsers.find(
      u => u.role === UserRoleEnum.KUNDE && u.associatedCustomerId === customer.id
    );

    if (!existingCustomerUser) {
      // Create a new user for this customer
      const newUserId = `user-kunde-${customer.id}`;
      const initials = `${customer.firstName.charAt(0)}${customer.lastName.charAt(0)}`.toUpperCase().slice(0, 2);
      const randomColor = avatarColors[Math.floor(Math.random() * avatarColors.length)];

      customerUsers.push({
        id: newUserId,
        avatarInitials: initials,
        avatarColor: randomColor,
        firstName: customer.firstName,
        lastName: customer.lastName,
        email: customer.email,
        password: 'kunde123', // Standard password for mock customer users
        role: UserRoleEnum.KUNDE,
        createdAt: customer.createdAt.toLocaleDateString('de-DE'), // Format Date object to string for User type
        associatedCustomerId: customer.id,
      });
    }
  });
  return customerUsers;
};


const App: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>([]); // Initialize with empty array
  const [users, setUsers] = useState<User[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]); // Initialize with empty array
  const [isLoggedIn, setIsLoggedIn] = useState(false); // New state for login status
  const [loggedInUserEmail, setLoggedInUserEmail] = useState<string | null>(null); // Store logged in user's email
  const navigate = useNavigate();

  // Fetch customers from the server on initial component mount
  useEffect(() => {
    const loadData = async () => {
      // Fetch both customers and transactions concurrently
      const [fetchedCustomers, fetchedTransactions] = await Promise.all([
        fetchCustomers(),
        fetchTransactions()
      ]);

      setCustomers(fetchedCustomers);
      setTransactions(fetchedTransactions);

      // Now that we have customers, we can generate the user list which includes customer-users
      setUsers(generateCustomerUsers(fetchedCustomers, BASE_MOCK_USERS));
    };
    loadData();
  }, []); // Empty dependency array means this runs only once

  // Find the current user based on loggedInUserEmail
  const currentUser = users.find(
    (user) => user.email === loggedInUserEmail
  ) || null;

  // Effect for initial redirection based on login status and user role
  useEffect(() => {
    if (!isLoggedIn) {
      if (window.location.hash !== '#/login') {
        navigate('/login', { replace: true });
      }
    } else if (currentUser) { // If logged in and currentUser is available
      if (currentUser.role === UserRoleEnum.KUNDE && currentUser.associatedCustomerId) {
        const expectedPath = `/customers/${currentUser.associatedCustomerId}`;
        // Check if the current hash path is *not* the expected customer path
        if (!window.location.hash.startsWith(`#${expectedPath}`)) {
          navigate(expectedPath, { replace: true }); // Use replace to prevent back button issues
        }
      } else if (window.location.hash === '#/login') {
        navigate('/', { replace: true });
      }
    }
  }, [isLoggedIn, navigate, currentUser]);

  const handleLogin = (email: string, passwordInput: string): boolean => {
    const user = users.find(
      (u) => u.email === email && u.password === passwordInput
    );
    if (user) {
      setIsLoggedIn(true);
      setLoggedInUserEmail(user.email);
      // Debugging: Log the associatedCustomerId to see what's being used for navigation
      console.log(`Login successful for user: ${user.email}. Role: ${user.role}. Associated Customer ID: ${user.associatedCustomerId}`);

      // Special redirection after login based on role
      if (user.role === UserRoleEnum.KUNDE && user.associatedCustomerId) {
        navigate(`/customers/${user.associatedCustomerId}`, { replace: true });
      } else {
        navigate('/', { replace: true }); // Default for Admin/Mitarbeiter
      }
      return true;
    }
    return false; // Login failed
  };

  const handleRegister = (email: string, password: string): boolean => {
    // 1. Check if user already exists
    if (users.some(u => u.email === email)) {
        alert("Ein Benutzer mit dieser E-Mail-Adresse existiert bereits.");
        return false;
    }

    // 2. Create new user and customer
    const now = new Date();
    const uniqueId = `reg-${now.getTime()}`;
    const newUserId = `user-${uniqueId}`;
    const associatedCustomerId = `cust-${uniqueId}`;
    const initials = (email.split('@')[0].substring(0, 2) || '??').toUpperCase();
    const avatarColors = ['bg-red-500', 'bg-orange-500', 'bg-purple-500', 'bg-indigo-500', 'bg-blue-500', 'bg-green-500', 'bg-teal-500', 'bg-fuchsia-500', 'bg-lime-500'];
    const randomColor = avatarColors[Math.floor(Math.random() * avatarColors.length)];

    const newUser: User = {
        id: newUserId,
        avatarInitials: initials,
        avatarColor: randomColor,
        firstName: email.split('@')[0], // Derive from email
        lastName: '', // Empty by default
        email: email,
        password: password,
        role: UserRoleEnum.KUNDE,
        createdAt: REFERENCE_DATE.toLocaleDateString('de-DE'), // Use reference date for consistency
        associatedCustomerId: associatedCustomerId,
    };

    const newCustomer: Customer = {
        id: associatedCustomerId,
        avatarInitials: initials,
        avatarColor: randomColor,
        firstName: newUser.firstName,
        lastName: newUser.lastName,
        email: email,
        phone: '',
        dogName: 'Unbekannt',
        chipNumber: '',
        balance: 0.00,
        totalTransactions: 0,
        level: TrainingLevelEnum.EINSTEIGER,
        createdAt: new Date(), // Use current date for new customer
        createdBy: 'System (Registrierung)',
        qrCodeData: `https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=https://example.com/customer/${associatedCustomerId}`,
        trainingProgress: [
          { id: 1, name: TrainingLevelEnum.EINSTEIGER, requiredHours: 6, completedHours: 0, status: 'Aktuell' },
          { id: 2, name: TrainingLevelEnum.GRUNDLAGEN, requiredHours: 12, completedHours: 0, status: 'Gesperrt' },
          { id: 3, name: TrainingLevelEnum.FORTGESCHRITTENE, requiredHours: 12, completedHours: 0, status: 'Gesperrt' },
          { id: 4, name: TrainingLevelEnum.MASTERCLASS, requiredHours: 12, completedHours: 0, status: 'Gesperrt' },
          { id: 5, name: TrainingLevelEnum.EXPERT, requiredHours: 100, completedHours: 0, status: 'Gesperrt' },
        ],
    };

    // 3. Update state
    setUsers(prevUsers => [...prevUsers, newUser]);
    setCustomers(prevCustomers => [...prevCustomers, newCustomer]);

    // 4. Log in the new user automatically
    setIsLoggedIn(true);
    setLoggedInUserEmail(newUser.email);
    navigate(`/customers/${associatedCustomerId}`, { replace: true });

    return true;
  };


  const handleUpdateCustomer = (updatedCustomer: Customer) => {
    setCustomers(prevCustomers =>
      prevCustomers.map(c => (c.id === updatedCustomer.id ? updatedCustomer : c))
    );
  };

  const handleAddTransaction = (newTransaction: Transaction) => {
    setTransactions(prevTransactions => [...prevTransactions, newTransaction]);
  };

  // User management functions
  const handleAddUser = (newUser: User) => {
    // If the new user is a 'Kunde' AND has an associatedCustomerId (set in UserManagement.tsx),
    // create a new customer for them in the customers state FIRST.
    if (newUser.role === UserRoleEnum.KUNDE && newUser.associatedCustomerId) {
      const avatarColors = ['bg-red-500', 'bg-orange-500', 'bg-purple-500', 'bg-indigo-500', 'bg-blue-500', 'bg-green-500', 'bg-teal-500', 'bg-fuchsia-500', 'bg-lime-500'];
      const randomColor = avatarColors[Math.floor(Math.random() * avatarColors.length)];

      const newCustomer: Customer = {
        id: newUser.associatedCustomerId, // Use the associatedCustomerId from the user
        avatarInitials: newUser.avatarInitials, // Use user's initials
        avatarColor: newUser.avatarColor || randomColor, // Use user's color or random
        firstName: newUser.firstName,
        lastName: newUser.lastName,
        email: newUser.email,
        phone: '', // Default value
        dogName: 'Unbekannt', // Default value
        chipNumber: '', // Default value
        balance: 0.00,
        totalTransactions: 0,
        level: TrainingLevelEnum.EINSTEIGER, // Default level
        createdAt: new Date(), // Use current date
        createdBy: currentUser?.firstName || 'System', // Use current user or System
        qrCodeData: `https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=https://example.com/customer/${newUser.associatedCustomerId}`,
        trainingProgress: [
          { id: 1, name: TrainingLevelEnum.EINSTEIGER, requiredHours: 6, completedHours: 0, status: 'Aktuell' },
          { id: 2, name: TrainingLevelEnum.GRUNDLAGEN, requiredHours: 12, completedHours: 0, status: 'Gesperrt' },
          { id: 3, name: TrainingLevelEnum.FORTGESCHRITTENE, requiredHours: 12, completedHours: 0, status: 'Gesperrt' },
          { id: 4, name: TrainingLevelEnum.MASTERCLASS, requiredHours: 12, completedHours: 0, status: 'Gesperrt' },
          { id: 5, name: TrainingLevelEnum.EXPERT, requiredHours: 100, completedHours: 0, status: 'Gesperrt' },
        ],
      };
      setCustomers(prevCustomers => {
        const updatedCustomers = [...prevCustomers, newCustomer];
        console.log('handleAddUser: New customer added. Current customers state:', updatedCustomers);
        return updatedCustomers;
      });
    }
    // THEN update the users state
    setUsers(prevUsers => [...prevUsers, newUser]); 
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUsers(prevUsers => {
      // If the updated user is a 'Kunde' and has an associatedCustomerId,
      // also update the corresponding customer's details
      if (updatedUser.role === UserRoleEnum.KUNDE && updatedUser.associatedCustomerId) {
        setCustomers(prevCustomers =>
          prevCustomers.map(customer => {
            if (customer.id === updatedUser.associatedCustomerId) {
              return {
                ...customer,
                firstName: updatedUser.firstName,
                lastName: updatedUser.lastName,
                email: updatedUser.email,
                // Add any other fields that should sync from User to Customer
                avatarInitials: updatedUser.avatarInitials,
                avatarColor: updatedUser.avatarColor,
              };
            }
            return customer;
          })
        );
      }
      return prevUsers.map(u => (u.id === updatedUser.id ? updatedUser : u));
    });
  };

  const handleDeleteUser = (userId: string) => {
    setUsers(prevUsers => {
      const userToDelete = prevUsers.find(u => u.id === userId);
      // If the deleted user is a 'Kunde' with an associatedCustomerId, also delete the customer
      if (userToDelete && userToDelete.role === UserRoleEnum.KUNDE && userToDelete.associatedCustomerId) {
        setCustomers(prevCustomers =>
          prevCustomers.filter(c => c.id !== userToDelete.associatedCustomerId)
        );
      }
      return prevUsers.filter(u => u.id !== userId);
    });
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setLoggedInUserEmail(null);
    alert('Sie wurden abgemeldet.');
    navigate('/login', { replace: true }); // Redirect to login page after logout
  };

  return (
    <div className="flex min-h-screen bg-gray-100">
      {isLoggedIn && currentUser ? (
        <>
          <Sidebar appName="Mantrailing Card" currentUser={currentUser} onLogout={handleLogout} />
          <main className="flex-1 md:ml-64 p-0">
            <Routes>
              {currentUser.role === UserRoleEnum.ADMIN ? (
                // Admin has full access
                <>
                  <Route path="/" element={<Dashboard customers={customers} transactions={transactions} />} />
                  <Route path="/customers" element={<CustomerManagement customers={customers} transactions={transactions} currentUser={currentUser} />} />
                  <Route
                    path="/customers/:id"
                    element={<CustomerDetails customers={customers} transactions={transactions} onUpdateCustomer={handleUpdateCustomer} onAddTransaction={handleAddTransaction} currentUser={currentUser} />}
                  />
                  <Route path="/reports" element={<Reports customers={customers} transactions={transactions} />} />
                  <Route path="/users" element={<UserManagement users={users} onAddUser={handleAddUser} onUpdateUser={handleUpdateUser} onDeleteUser={handleDeleteUser} />} />
                  <Route path="*" element={<Dashboard customers={customers} transactions={transactions} />} /> {/* Fallback for Admin */}
                </>
              ) : currentUser.role === UserRoleEnum.MITARBEITER ? (
                // Mitarbeiter has restricted access
                <>
                  <Route path="/" element={<Dashboard customers={customers} transactions={transactions} />} />
                  <Route path="/customers" element={<CustomerManagement customers={customers} transactions={transactions} currentUser={currentUser} />} />
                  <Route
                    path="/customers/:id"
                    element={<CustomerDetails customers={customers} transactions={transactions} onUpdateCustomer={handleUpdateCustomer} onAddTransaction={handleAddTransaction} currentUser={currentUser} />}
                  />
                  {/* Redirect any restricted path or unknown path for Mitarbeiter to dashboard */}
                  <Route path="/reports" element={<Dashboard customers={customers} transactions={transactions} />} />
                  <Route path="/users" element={<Dashboard customers={customers} transactions={transactions} />} />
                  <Route path="*" element={<Dashboard customers={customers} transactions={transactions} />} /> {/* Fallback for Mitarbeiter */}
                </>
              ) : currentUser.role === UserRoleEnum.KUNDE && currentUser.associatedCustomerId ? (
                // Kunde has access only to their own customer details, enforced by internal component logic and redirects
                <>
                  {/* Dynamic route for *any* customer ID. The CustomerDetails component will authorize. */}
                  <Route
                    path="/customers/:id"
                    element={<CustomerDetails customers={customers} transactions={transactions} onUpdateCustomer={handleUpdateCustomer} onAddTransaction={handleAddTransaction} currentUser={currentUser} />}
                  />
                  {/* Redirect root path to their own specific customer page */}
                  <Route path="/" element={<Navigate replace to={`/customers/${currentUser.associatedCustomerId}`} />} />
                  {/* Catch-all for any other path not explicitly handled, redirects to their own customer page */}
                  <Route path="*" element={<Navigate replace to={`/customers/${currentUser.associatedCustomerId}`} />} />
                </>
              ) : (
                // Fallback for any other unexpected logged-in state (e.g., customer role without associated ID, though type system should prevent this state for a logged-in user)
                <Route path="*" element={<Dashboard customers={customers} transactions={transactions} />} />
              )}
            </Routes>
          </main>
        </>
      ) : (
        // Not logged in
        <Routes>
          <Route path="/login" element={<LoginPage onLogin={handleLogin} onRegister={handleRegister} />} />
          <Route path="*" element={<LoginPage onLogin={handleLogin} onRegister={handleRegister} />} />
        </Routes>
      )}
    </div>
  );
};

export default App;

import React from 'react';
import Card from '../components/Card';
import StatCard from '../components/StatCard';
import { REFERENCE_DATE } from '../constants'; // Only REFERENCE_DATE remains in constants
import Avatar from '../components/Avatar';
import { ArrowUpCircleIcon, ArrowDownCircleIcon, UsersIcon, DollarSignIcon, ClipboardIcon, RepeatIcon } from '../components/Icons';
import { Link } from 'react-router-dom';
import { parseDateString, isSameDay, isSameMonth } from '../utils';
import { Customer, Transaction } from '../types'; // Import types

interface DashboardProps {
  customers: Customer[];
  transactions: Transaction[];
}

const Dashboard: React.FC<DashboardProps> = ({ customers, transactions }) => {
  // Dynamic calculations for Dashboard Stats
  const totalCustomers = customers.length;
  const totalBalance = customers.reduce((sum, customer) => sum + customer.balance, 0);

  const today = REFERENCE_DATE;
  const currentMonthTransactions = transactions.filter(t => {
    const transactionDate = parseDateString(t.date);
    return transactionDate && isSameMonth(transactionDate, today);
  });
  const todayTransactions = transactions.filter(t => {
    const transactionDate = parseDateString(t.date);
    return transactionDate && isSameDay(transactionDate, today);
  });

  const dashboardStats = [
    { title: 'Kunden Gesamt', value: totalCustomers, icon: UsersIcon, color: 'bg-green-100 text-green-700' },
    { title: 'Guthaben gesamt', value: totalBalance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' }), icon: DollarSignIcon, color: 'bg-orange-100 text-orange-700' },
    { title: 'Transaktionen Heute', value: todayTransactions.length, icon: ClipboardIcon, color: 'bg-blue-100 text-blue-700' },
    { title: 'Transaktionen Monat', value: currentMonthTransactions.length, icon: RepeatIcon, color: 'bg-purple-100 text-purple-700' },
  ];

  // Aktuelle Kunden (based on createdAt, max 5, scrollable)
  const recentCustomers = [...customers]
    .sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime()) // Sort descending by Date object
    .slice(0, 5); // Take top 5

  // Letzte Transaktionen (max 5, scrollable)
  const latestTransactions = [...transactions]
    .sort((a, b) => {
      const dateA = parseDateString(a.date);
      const dateB = parseDateString(b.date);
      if (!dateA || !dateB) return 0; // Handle invalid dates
      return dateB.getTime() - dateA.getTime(); // Sort descending
    })
    .slice(0, 5); // Take top 5

  return (
    <div className="p-6 md:p-8 lg:p-10">
      <h1 className="text-3xl font-bold text-gray-900 mb-2">Willkommen, Christian Christian!</h1>
      <p className="text-gray-600 mb-8">Übersicht ihrer Trails-Wertkarten</p>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        {dashboardStats.map((stat, index) => (
          <StatCard
            key={index}
            title={stat.title}
            value={stat.value}
            icon={stat.icon}
            color={stat.color}
          />
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Aktuelle Kunden */}
        <Card>
          <h2 className="text-xl font-semibold text-gray-900 mb-4">Aktuelle Kunden</h2>
          <div className="space-y-4 max-h-96 overflow-y-auto custom-scrollbar"> {/* Changed max-h-72 to max-h-96 */}
            {recentCustomers.length === 0 ? (
              <p className="text-gray-500 text-sm">Keine aktuellen Kunden gefunden.</p>
            ) : (
              recentCustomers.map((customer) => (
                <Link to={`/customers/${customer.id}`} key={customer.id} className="flex items-center justify-between p-3 bg-gray-50 hover:bg-gray-100 rounded-lg transition-colors duration-200">
                  <div className="flex items-center">
                    <Avatar initials={customer.avatarInitials} color={customer.avatarColor} size="md" className="mr-3" />
                    <div>
                      <p className="font-medium text-gray-900">{customer.firstName} {customer.lastName}</p>
                      <p className="text-sm text-gray-500">{customer.dogName}</p>
                    </div>
                  </div>
                  <p className="font-semibold text-gray-800">{customer.balance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}</p>
                </Link>
              ))
            )}
          </div>
        </Card>

        {/* Letzte Transaktionen */}
        <Card>
          <h2 className="text-xl font-semibold text-gray-900 mb-4">Letzte Transaktionen</h2>
          <div className="space-y-4 max-h-96 overflow-y-auto custom-scrollbar"> {/* Changed max-h-72 to max-h-96 */}
            {latestTransactions.length === 0 ? (
              <p className="text-gray-500 text-sm">Keine aktuellen Transaktionen gefunden.</p>
            ) : (
              latestTransactions.map((transaction) => {
                const customer = customers.find(c => c.id === transaction.customerId);
                const isRecharge = transaction.type === 'recharge';
                const TransactionIcon = isRecharge ? ArrowUpCircleIcon : ArrowDownCircleIcon;
                const iconColor = isRecharge ? 'text-green-500' : 'text-red-500';
                const amountColor = isRecharge ? 'text-green-700' : 'text-red-700';
                const amountSign = isRecharge ? '+' : '-'; // Changed to dynamically show + or -

                return (
                  <div key={transaction.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                    <div className="flex items-center">
                      <span className={`p-2 rounded-full bg-gray-200 mr-3 ${iconColor}`}>
                        <TransactionIcon className="h-5 w-5" />
                      </span>
                      <div>
                        <p className="font-medium text-gray-900">{customer?.firstName} {customer?.lastName}</p>
                        <p className="text-sm text-gray-500">{transaction.date} - {transaction.description}</p>
                      </div>
                    </div>
                    <p className={`font-semibold ${amountColor}`}>
                      {amountSign}{Math.abs(transaction.amount).toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
                    </p>
                  </div>
                );
              })
            )}
          </div>
        </Card>
      </div>
    </div>
  );
};

