                              </div>
                            </>
                          );
                        })()
                      ) : (
                        <>
                          <p className="text-sm text-gray-600 mb-3">Fortschritt: {section.completedHours} / {section.requiredHours} Trails</p>
                          <div className="flex flex-wrap gap-2">
                            {Array.from({ length: section.completedHours }).map((_, i) => (<TrainingPawIcon key={i} filled={true} />))}
                            {Array.from({ length: section.requiredHours - section.completedHours }).map((_, i) => (<TrainingPawIcon key={`empty-${i}`} filled={false} />))}
                          </div>
                        </>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </Card>
        </div>
        <div className="lg:col-span-1 space-y-6">
          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Konto</h2>
            <div className="space-y-2 text-gray-700">
              <div className="flex justify-between"><span>Erstellt am</span><span className="font-bold">{createdAtFormatted}</span></div>
              <div className="flex justify-between"><span>Kunden-ID</span><span className="font-bold">{customer.id}</span></div>
            </div>
          </Card>

          <Card className="text-center">
            <h2 className="text-xl font-semibold text-gray-900 mb-4">QR-Code</h2>
            <QRCodeDisplay dataUrl={customer.qrCodeData} className="mb-3" />
            <p className="text-sm text-gray-600">Scannen, um diese Kundenkarte schnell aufzurufen.</p>
          </Card>
        </div>
      </div>
      <TransactionConfirmationModal
        isOpen={showConfirmationModal}
        onClose={() => setShowConfirmationModal(false)}
        onConfirm={handleConfirmTransaction}
        data={transactionData}
      />
      <TransactionTypeSelectionModal
        isOpen={showTransactionTypeModal}
        onClose={() => setShowTransactionTypeModal(false)}
        onSelectType={handleSelectTransactionType}
      />
      <CustomerFormModal
        isOpen={isEditModalOpen}
        onClose={() => setIsEditModalOpen(false)}
        onSubmit={handleUpdateStammdaten}
        customerToEdit={customer}
      />
      <TransactionHistoryModal
        isOpen={isTransactionHistoryModalOpen}
        onClose={() => setIsTransactionHistoryModalOpen(false)}
        transactions={customerTransactions}
        customerName={`${customer.firstName} ${customer.lastName}`}
      />
    </div>
  );
};

export default CustomerDetails;

import { Customer, Transaction } from '../types';

const API_BASE_URL = 'http://localhost:3001/api';

export const fetchCustomers = async (): Promise<Customer[]> => {
  try {
    const response = await fetch(`${API_BASE_URL}/customers`);
    if (!response.ok) {
      // Throws an error which will be caught by the calling function
      throw new Error(`Network response was not ok: ${response.statusText}`);
    }
    // Prisma returns dates as ISO strings, so we need to convert them to Date objects
    const data = await response.json();
    return data.map((customer: any) => ({
      ...customer,
      createdAt: new Date(customer.createdAt), // Convert string to Date object
    }));
  } catch (error) {
    console.error("Failed to fetch customers:", error);
    // Return an empty array to prevent the app from crashing if the server is down.
    // A more robust solution would involve proper error state management in the UI.
    return [];
  }
};

export const fetchTransactions = async (): Promise<Transaction[]> => {
  try {
    const response = await fetch(`${API_BASE_URL}/transactions`);
    if (!response.ok) {
      throw new Error(`Network response was not ok: ${response.statusText}`);
    }
    const data: Transaction[] = await response.json();
    return data;
  } catch (error) {
    console.error("Failed to fetch transactions:", error);
    return [];
  }
};

import express from 'express';
import cors from 'cors';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();
const app: express.Application = express();
const port = 3001;

app.use(cors());
app.use(express.json());

// --- API Endpoints ---

// GET all customers
app.get('/api/customers', async (req, res) => {
  try {
    console.log("GET /api/customers - Request received. Querying database...");
    const customers = await prisma.customer.findMany({
      include: {
        trainingProgress: true, // Include related training progress
      },
    });
    console.log(`Successfully fetched ${customers.length} customers.`);
    res.json(customers);
  } catch (error) {
    console.error("Failed to fetch customers:", error);
    res.status(500).json({ error: "An error occurred while fetching customers." });
  }
});

// GET all transactions
app.get('/api/transactions', async (req, res) => {
  try {
    console.log("GET /api/transactions - Request received. Querying database...");
    const transactions = await prisma.transaction.findMany();
    console.log(`Successfully fetched ${transactions.length} transactions.`);
    res.json(transactions);
  } catch (error) {
    console.error("Failed to fetch transactions:", error);
    res.status(500).json({ error: "An error occurred while fetching transactions." });
  }
});


// Health check endpoint
app.get('/api/health', (req, res) => {
    res.status(200).send('Server is healthy');
});


const server = app.listen(port, () => {
  console.log(`🚀 Server is running at http://localhost:${port}`);
  console.log("Connected to the database via Prisma Client.");
});

// Graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM signal received: closing HTTP server');
  server.close(async () => {
    console.log('HTTP server closed');
    await prisma.$disconnect();
    console.log('Prisma Client disconnected');
    process.exit(0);
  });
});

