// Use a relative path for the API base URL.
// When deployed, the frontend and backend will be on the same domain,
// and Vercel will correctly proxy requests from /api/... to the serverless functions.
const API_BASE_URL = '/api';

export const fetchCustomers = async (): Promise<Customer[]> => {
  try {
    const response = await fetch(`${API_BASE_URL}/customers`);
    if (!response.ok) {
      throw new Error(`Network response was not ok: ${response.statusText}`);
    }
    const data = await response.json();
    // Convert date strings from the API (which are in ISO format) to Date objects
    return data.map((customer: any) => ({
      ...customer,
      createdAt: new Date(customer.createdAt),
    }));
  } catch (error) {
    console.error("Failed to fetch customers:", error);
    return []; // Return an empty array on failure to prevent app crash
  }
};

export const fetchTransactions = async (): Promise<Transaction[]> => {
  try {
    const response = await fetch(`${API_BASE_URL}/transactions`);
    if (!response.ok) {
      throw new Error(`Network response was not ok: ${response.statusText}`);
    }
    const data: Transaction[] = await response.json();
    return data;
  } catch (error)
    console.error("Failed to fetch transactions:", error);
    return []; // Return an empty array on failure
  }
};

