const app = express();

// Note: Vercel automatically handles the port.
// You don't need to define it.

app.use(cors());
app.use(express.json());

// --- API Endpoints ---

// GET all customers
// FIX: Using explicit express.Request and express.Response types.
app.get('/api/customers', async (req: express.Request, res: express.Response) => {
  try {
    const customers = await prisma.customer.findMany({
      include: {
        trainingProgress: true,
      },
      orderBy: {
        createdAt: 'desc',
      }
    });
    res.json(customers);
  } catch (error) {
    console.error("Failed to fetch customers:", error);
    res.status(500).json({ error: "An error occurred while fetching customers." });
  }
});

// GET all transactions
// FIX: Using explicit express.Request and express.Response types.
app.get('/api/transactions', async (req: express.Request, res: express.Response) => {
  try {
    const transactions = await prisma.transaction.findMany({
        orderBy: {
            // Assuming the 'date' field can be sorted lexically if in YYYY-MM-DD or similar format
            // For DD.MM.YYYY this might not sort correctly. 
            // A better approach would be to store dates as DateTime in the DB.
            // For now, we leave it as is.
            date: 'desc'
        }
    });
    res.json(transactions);
  } catch (error) {
    console.error("Failed to fetch transactions:", error);
    res.status(500).json({ error: "An error occurred while fetching transactions." });
  }
});

// Health check endpoint
// FIX: Using explicit express.Request and express.Response types.
app.get('/api/health', (req: express.Request, res: express.Response) => {
    res.status(200).send('Server is healthy and running.');
});

// Vercel exports the app instance
export default app;

import { Customer, Transaction } from '../types';

// Use a relative path for the API base URL.
// When deployed, the frontend and backend will be on the same domain,
// and Vercel will correctly proxy requests from /api/... to the serverless functions.
const API_BASE_URL = '/api';

export const fetchCustomers = async (): Promise<Customer[]> => {
  try {
    const response = await fetch(`${API_BASE_URL}/customers`);
    if (!response.ok) {
      throw new Error(`Network response was not ok: ${response.statusText}`);
    }
    const data = await response.json();
    // Convert date strings from the API (which are in ISO format) to Date objects
    return data.map((customer: any) => ({
      ...customer,
      createdAt: new Date(customer.createdAt),
    }));
  } catch (error) {
    console.error("Failed to fetch customers:", error);
    return []; // Return an empty array on failure to prevent app crash
  }
};

export const fetchTransactions = async (): Promise<Transaction[]> => {
  try {
    const response = await fetch(`${API_BASE_URL}/transactions`);
    if (!response.ok) {
      throw new Error(`Network response was not ok: ${response.statusText}`);
    }
    const data: Transaction[] = await response.json();
    return data;
    // FIX: Corrected syntax for the catch block.
  } catch (error) {
    console.error("Failed to fetch transactions:", error);
    return []; // Return an empty array on failure
  }
};

